{
  "name": "Madex Status",
  "description": "A professional system monitoring and public status dashboard for Madex IT, featuring dark mode, site management, and Discord integration.",
  "requestFramePermissions": [
    "notifications"
  ]
}

export type StatusType = 'operational' | 'partial' | 'down';

export interface Incident {
  id: string;
  date: string;
  title: string;
  description: string;
}

export interface PublicSystem {
  id: string;
  name: string;
  status: StatusType;
  history: StatusType[]; // 30 days
  incidents: Incident[];
}

export interface MonitoredSite {
  id: string;
  companyName: string;
  url: string;
  status: 'online' | 'offline' | 'warning';
  interval: number; // minutes
  timeout: number; // seconds
  method: 'GET' | 'POST' | 'HEAD';
  statusRange: string; // e.g., "200-399"
  keyword?: string;
  lastChecked?: string;
  responseTime: number[]; // Last 24 points
  history: ('online' | 'offline' | 'warning')[]; // 30 points
}

export interface AppSettings {
  discordWebhook: string;
}

export interface AppState {
  publicSystems: PublicSystem[];
  monitoredSites: MonitoredSite[];
  settings: AppSettings;
}

import React from 'react';
import { PublicSystem, MonitoredSite, StatusType } from './types';

export const BRAND_COLOR = '#028D86';

const generateHistory = (length: number, failChance: number = 0.05): StatusType[] => {
  return Array.from({ length }, () => {
    const r = Math.random();
    if (r < failChance / 2) return 'down';
    if (r < failChance) return 'partial';
    return 'operational';
  });
};

const generateSiteHistory = (length: number): ('online' | 'offline' | 'warning')[] => {
  return Array.from({ length }, () => {
    const r = Math.random();
    if (r < 0.02) return 'offline';
    if (r < 0.05) return 'warning';
    return 'online';
  });
};

export const INITIAL_PUBLIC_SYSTEMS: PublicSystem[] = [
  { id: '1', name: 'Domain', status: 'operational', history: generateHistory(30), incidents: [] },
  { id: '2', name: 'Hosting', status: 'operational', history: generateHistory(30), incidents: [] },
  { id: '3', name: 'Server', status: 'operational', history: generateHistory(30), incidents: [] },
  { id: '4', name: 'Email', status: 'operational', history: generateHistory(30), incidents: [] },
  { id: '5', name: 'APPs', status: 'operational', history: generateHistory(30), incidents: [] },
];

export const INITIAL_MONITORED_SITES: MonitoredSite[] = [
  {
    id: 's1',
    companyName: 'Madex IT',
    url: 'https://madex-it.ch',
    status: 'online',
    interval: 5,
    timeout: 10,
    method: 'GET',
    statusRange: '200-399',
    responseTime: Array.from({ length: 24 }, () => Math.floor(Math.random() * 200) + 50),
    history: generateSiteHistory(30),
  },
  {
    id: 's2',
    companyName: 'Swiss Logistics',
    url: 'https://swiss-log.com',
    status: 'online',
    interval: 10,
    timeout: 30,
    method: 'GET',
    statusRange: '200-399',
    responseTime: Array.from({ length: 24 }, () => Math.floor(Math.random() * 500) + 100),
    history: generateSiteHistory(30),
  }
];

import { AppState, PublicSystem, MonitoredSite, AppSettings } from './types';
import { INITIAL_PUBLIC_SYSTEMS, INITIAL_MONITORED_SITES } from './constants';

const STORAGE_KEY = 'madex_status_db';

export const getStore = (): AppState => {
  const data = localStorage.getItem(STORAGE_KEY);
  if (!data) {
    const initialState: AppState = {
      publicSystems: INITIAL_PUBLIC_SYSTEMS,
      monitoredSites: INITIAL_MONITORED_SITES,
      settings: { discordWebhook: '' }
    };
    saveStore(initialState);
    return initialState;
  }
  return JSON.parse(data);
};

export const saveStore = (state: AppState) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
};

export const notifyDiscord = async (webhookUrl: string, message: string) => {
  if (!webhookUrl) return;
  try {
    await fetch(webhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ content: `🚀 **Madex Status Alert**\n${message}` }),
    });
  } catch (error) {
    console.error('Discord notification failed:', error);
  }
};

