import React from 'react';
import { StatusType } from '../types';

interface StatusBarProps {
  history: (StatusType | 'online' | 'offline' | 'warning')[];
}

const StatusBar: React.FC<StatusBarProps> = ({ history }) => {
  return (
    <div className="flex items-end gap-[2px] h-10 w-full group">
      {history.slice(-30).map((status, i) => {
        let color = 'bg-gray-800';
        if (status === 'operational' || status === 'online') color = 'bg-emerald-500';
        if (status === 'partial' || status === 'warning') color = 'bg-orange-500';
        if (status === 'down' || status === 'offline') color = 'bg-rose-500';

        return (
          <div
            key={i}
            className={`${color} flex-1 h-full rounded-sm transition-all hover:scale-y-110 relative group/item`}
          >
             <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-2 py-1 bg-black text-[10px] rounded opacity-0 group-hover/item:opacity-100 pointer-events-none whitespace-nowrap z-10 border border-dark-700 shadow-xl">
                Day {30 - history.length + i + 1}: {status}
             </div>
          </div>
        );
      })}
    </div>
  );
};

export default StatusBar;

import React from 'react';
import { Link } from 'react-router-dom';
import { AppState } from '../types';
import StatusBar from '../components/StatusBar';
import { CheckCircle, AlertTriangle, XCircle, Shield } from '../components/Icons';

interface Props {
  state: AppState;
}

