export default PublicStatus;

import React from 'react';
import { AppState } from '../types';
import { CheckCircle, AlertTriangle, XCircle, Globe } from '../components/Icons';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface Props {
  state: AppState;
}

const Dashboard: React.FC<Props> = ({ state }) => {
  const sites = state.monitoredSites;
  const total = sites.length;
  const operational = sites.filter(s => s.status === 'online').length;
  const warnings = sites.filter(s => s.status === 'warning').length;
  const downtime = sites.filter(s => s.status === 'offline').length;

  const chartData = sites.map(s => ({
    name: s.companyName,
    avg: s.responseTime.reduce((a, b) => a + b, 0) / s.responseTime.length
  }));

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold">System Overview</h1>
          <p className="text-zinc-500">Real-time performance metrics for all monitored sites.</p>
        </div>
        <div className="flex items-center gap-2 bg-dark-900 border border-dark-800 px-4 py-2 rounded-xl text-xs font-medium text-zinc-400">
           <span className="w-2 h-2 bg-emerald-500 rounded-full animate-ping"></span>
           Live Monitoring Active
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard title="Total Monitors" value={total} icon={<Globe className="w-5 h-5 text-brand" />} />
        <StatCard title="Operational" value={operational} icon={<CheckCircle className="w-5 h-5 text-emerald-500" />} />
        <StatCard title="Warnings" value={warnings} icon={<AlertTriangle className="w-5 h-5 text-orange-500" />} />
        <StatCard title="Downtime" value={downtime} icon={<XCircle className="w-5 h-5 text-rose-500" />} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Response Time Chart */}
        <div className="lg:col-span-2 bg-dark-900 border border-dark-800 rounded-2xl p-6 shadow-xl">
          <h3 className="text-lg font-bold mb-6">Average Response Time (ms)</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <XAxis dataKey="name" stroke="#52525b" fontSize={12} tickLine={false} axisLine={false} />
                <YAxis stroke="#52525b" fontSize={12} tickLine={false} axisLine={false} tickFormatter={(val) => `${val}ms`} />
                <Tooltip
                  cursor={{ fill: 'rgba(255,255,255,0.05)' }}
                  contentStyle={{ backgroundColor: '#121212', border: '1px solid #2d2d2d', borderRadius: '8px' }}
                />
                <Bar dataKey="avg" radius={[4, 4, 0, 0]}>
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={BRAND_COLOR_VAR(index)} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Quick List */}
        <div className="bg-dark-900 border border-dark-800 rounded-2xl p-6 shadow-xl">
            <h3 className="text-lg font-bold mb-4">Site Status Summary</h3>
            <div className="space-y-4 max-h-[310px] overflow-y-auto custom-scrollbar pr-2">
                {sites.map(site => (
                    <div key={site.id} className="flex items-center justify-between p-3 rounded-xl bg-dark-950/50 border border-dark-800">
                        <div className="min-w-0 flex-1 mr-3">
                            <p className="text-sm font-semibold truncate">{site.companyName}</p>
                            <p className="text-xs text-zinc-500 truncate">{site.url}</p>
                        </div>
                        <div className={`px-2 py-1 rounded text-[10px] font-bold uppercase ${site.status === 'online' ? 'bg-emerald-500/10 text-emerald-500' : site.status === 'warning' ? 'bg-orange-500/10 text-orange-500' : 'bg-rose-500/10 text-rose-500'}`}>
                            {site.status}
                        </div>
                    </div>
                ))}
            </div>
        </div>
      </div>
    </div>
  );
};

const BRAND_COLOR_VAR = (idx: number) => {
    const colors = ['#028D86', '#03a59e', '#01736d', '#02b8af'];
    return colors[idx % colors.length];
};

const StatCard = ({ title, value, icon }: { title: string, value: number, icon: React.ReactNode }) => (
  <div className="bg-dark-900 border border-dark-800 rounded-2xl p-6 shadow-xl flex items-center justify-between group hover:border-brand/50 transition-colors">
    <div>
      <p className="text-sm text-zinc-500 font-medium">{title}</p>
      <p className="text-3xl font-bold mt-1">{value}</p>
    </div>
    <div className="p-3 bg-dark-950 border border-dark-800 rounded-xl group-hover:scale-110 transition-transform">
      {icon}
    </div>
  </div>
);

export default Dashboard;

import React, { useState } from 'react';
import { AppState, MonitoredSite } from '../types';
import StatusBar from '../components/StatusBar';

interface Props {
  state: AppState;
  onUpdate: (sites: MonitoredSite[]) => void;
}

const AllSites: React.FC<Props> = ({ state, onUpdate }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingSite, setEditingSite] = useState<MonitoredSite | null>(null);

  const [formData, setFormData] = useState<Partial<MonitoredSite>>({
    companyName: '',
    url: '',
    interval: 5,
    timeout: 30,
    method: 'GET',
    statusRange: '200-399',
    keyword: ''
  });

  const handleOpenAdd = () => {
    setEditingSite(null);
    setFormData({
      companyName: '',
      url: '',
      interval: 5,
      timeout: 30,
      method: 'GET',
      statusRange: '200-399',
      keyword: ''
    });
    setIsModalOpen(true);
  };

  const handleOpenEdit = (site: MonitoredSite) => {
    setEditingSite(site);
    setFormData(site);
    setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to delete this monitor?')) {
      onUpdate(state.monitoredSites.filter(s => s.id !== id));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingSite) {
      const updated = state.monitoredSites.map(s => s.id === editingSite.id ? { ...s, ...formData } as MonitoredSite : s);
      onUpdate(updated);
    } else {
      const newSite: MonitoredSite = {
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        status: 'online',
        responseTime: [150],
        history: Array(30).fill('online'),
      } as MonitoredSite;
      onUpdate([...state.monitoredSites, newSite]);
    }
    setIsModalOpen(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">Monitored Sites</h1>
          <p className="text-zinc-500">Configure and manage external service monitoring.</p>
        </div>
        <button
          onClick={handleOpenAdd}
          className="bg-brand hover:bg-opacity-90 text-white px-5 py-2.5 rounded-xl font-bold transition-all shadow-[0_0_20px_rgba(2,141,134,0.3)]"
        >
          + Add Website
        </button>
      </div>

      <div className="grid gap-4">
        {state.monitoredSites.map(site => (
          <div key={site.id} className="bg-dark-900 border border-dark-800 rounded-2xl p-6 hover:border-brand/30 transition-all flex flex-col md:flex-row md:items-center gap-6 shadow-lg">
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-3 mb-1">
                <h3 className="font-bold text-lg truncate">{site.companyName}</h3>
                <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-widest ${site.status === 'online' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                    {site.status}
                </span>
              </div>
              <p className="text-zinc-500 text-sm truncate font-mono">{site.url}</p>
              <div className="mt-4">
                 <StatusBar history={site.history} />
              </div>
            </div>

            <div className="flex flex-col md:items-end gap-1 md:w-48">
              <p className="text-xs text-zinc-500">Check Interval: <span className="text-zinc-200">{site.interval}m</span></p>
              <p className="text-xs text-zinc-500">Avg Response: <span className="text-zinc-200">{(site.responseTime.reduce((a,b)=>a+b,0)/site.responseTime.length).toFixed(0)}ms</span></p>
              <div className="flex gap-2 mt-3">
                <button onClick={() => handleOpenEdit(site)} className="text-sm font-medium text-zinc-400 hover:text-white transition-colors">Edit</button>
                <button onClick={() => handleDelete(site.id)} className="text-sm font-medium text-zinc-600 hover:text-rose-500 transition-colors">Delete</button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Modal Overlay */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-dark-900 border border-dark-800 w-full max-w-lg rounded-2xl p-8 shadow-2xl">
            <h2 className="text-xl font-bold mb-6">{editingSite ? 'Edit Website' : 'Add New Website'}</h2>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-xs font-bold text-zinc-500 uppercase tracking-wider">Company Name</label>
                  <input
                    required
                    type="text"
                    value={formData.companyName}
                    onChange={e => setFormData({ ...formData, companyName: e.target.value })}
