interface Props {
  state: AppState;
  onUpdateSettings: (s: AppSettings) => void;
  onUpdatePublic: (p: PublicSystem[]) => void;
}

const Settings: React.FC<Props> = ({ state, onUpdateSettings, onUpdatePublic }) => {
  const [webhook, setWebhook] = useState(state.settings.discordWebhook);
  const [isSaved, setIsSaved] = useState(false);

  const handleSaveDiscord = () => {
    onUpdateSettings({ ...state.settings, discordWebhook: webhook });
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 2000);
  };

  const togglePublicStatus = (id: string) => {
      const nextStatus = (status: string) => {
          if (status === 'operational') return 'partial';
          if (status === 'partial') return 'down';
          return 'operational';
      };

      const updated = state.publicSystems.map(s => s.id === id ? { ...s, status: nextStatus(s.status) as any } : s);
      onUpdatePublic(updated);
  };

