  interval: number; // minuta
  timeout: number; // sekonda
  method: 'GET' | 'POST' | 'HEAD';
  statusRange: string;
  keyword?: string;
  lastChecked?: string;
  responseTime: number[]; // 24 pikat e fundit
  history: ('online' | 'offline' | 'warning')[]; // 30 ditë
}

export interface AppSettings {
  discordWebhook: string;
}

export interface AppState {
  publicSystems: PublicSystem[];
  monitoredSites: MonitoredSite[];
  incidents: Incident[];
  settings: AppSettings;
}

import { AppState, Incident } from './types';
import { INITIAL_PUBLIC_SYSTEMS, INITIAL_MONITORED_SITES } from './constants';

const STORAGE_KEY = 'madex_status_db';

export const getStore = (): AppState => {
  const data = localStorage.getItem(STORAGE_KEY);
  if (!data) {
    const initialState: AppState = {
      publicSystems: INITIAL_PUBLIC_SYSTEMS,
      monitoredSites: INITIAL_MONITORED_SITES,
      incidents: [],
      settings: { discordWebhook: '' }
    };
    saveStore(initialState);
    return initialState;
  }
  const parsed = JSON.parse(data);
  // Sigurohemi që fusha e incidenteve ekziston për migrim të dhënash
  if (!parsed.incidents) parsed.incidents = [];
  return parsed;
};

export const saveStore = (state: AppState) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
};

export const notifyDiscord = async (webhookUrl: string, message: string) => {
  if (!webhookUrl) return;
  try {
    await fetch(webhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ content: `🚀 **Madex Status Alert**\n${message}` }),
    });
  } catch (error) {
    console.error('Discord notification failed:', error);
  }
};

import React from 'react';
import { StatusType } from '../types';

interface StatusBarProps {
  history: (StatusType | 'online' | 'offline' | 'warning')[];
}

const StatusBar: React.FC<StatusBarProps> = ({ history }) => {
  const today = new Date();

  return (
    <div className="flex items-end gap-[2px] h-10 w-full group">
      {history.slice(-30).map((status, i) => {
        const barDate = new Date();
        barDate.setDate(today.getDate() - (29 - i));
        const dateString = barDate.toLocaleDateString('sq-AL', { day: '2-digit', month: 'short' });

        let color = 'bg-gray-800';
        if (status === 'operational' || status === 'online') color = 'bg-emerald-500';
        if (status === 'partial' || status === 'warning') color = 'bg-orange-500';
        if (status === 'down' || status === 'offline') color = 'bg-rose-500';

        return (
          <div
            key={i}
            className={`${color} flex-1 h-full rounded-sm transition-all hover:scale-y-110 relative group/item`}
          >
             <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-2 py-1 bg-black text-[10px] rounded opacity-0 group-hover/item:opacity-100 pointer-events-none whitespace-nowrap z-10 border border-dark-700 shadow-xl">
                {dateString}: {status}
             </div>
          </div>
        );
      })}
    </div>
  );
};

