  onUpdateIncidents: (i: Incident[]) => void;
}

const Settings: React.FC<Props> = ({ state, onUpdateSettings, onUpdatePublic, onUpdateIncidents }) => {
  const [webhook, setWebhook] = useState(state.settings.discordWebhook);
  const [isSaved, setIsSaved] = useState(false);

  // States for Incident Form
  const [newIncident, setNewIncident] = useState({ title: '', description: '', date: new Date().toISOString().split('T')[0] });

