                <button 
                  onClick={() => setActiveFilter('all')}
                  className="text-xs font-bold text-brand hover:underline"
                >
                  Clear Filter
                </button>
              )}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-[600px] overflow-y-auto custom-scrollbar pr-2">
                {filteredSites.map(site => (
                    <button 
                      key={site.id} 
                      onClick={() => navigate(`/sites/${site.id}`)}
                      className="flex items-center justify-between p-5 rounded-2xl bg-dark-950 border border-dark-800 hover:border-brand/40 transition-all group shadow-sm text-left w-full"
                    >
                        <div className="min-w-0 flex-1 mr-4">
                            <div className="flex items-center gap-2 mb-1">
                              <span className={`w-2 h-2 rounded-full ${site.status === 'online' ? 'bg-emerald-500' : site.status === 'warning' ? 'bg-orange-500' : 'bg-rose-500'}`}></span>
                              <p className="text-base font-bold truncate group-hover:text-brand transition-colors">{site.companyName}</p>
                            </div>
                            <p className="text-xs text-zinc-500 truncate font-mono">{site.url}</p>
                        </div>
                        <div className="flex flex-col items-end gap-1.5">
                          <div className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider ${
                            site.status === 'online' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 
                            site.status === 'warning' ? 'bg-orange-500/10 text-orange-400 border border-orange-500/20' : 
                            'bg-rose-500/10 text-rose-400 border border-rose-500/20'
                          }`}>
                              {site.status}
                          </div>
                          <span className="text-xs font-mono font-bold text-zinc-400">{site.responseTime[site.responseTime.length-1]}ms</span>
                        </div>
                    </button>
                ))}
                {filteredSites.length === 0 && (
                  <div className="col-span-full text-center py-24 bg-dark-950/50 rounded-3xl border border-dashed border-dark-800">
                    <p className="text-zinc-500 italic">No monitors match the current filter.</p>
                  </div>
                )}
            </div>
        </div>

        {/* Network Performance Trend - SMALLER (1/3) */}
        <div className="bg-dark-900 border border-dark-800 rounded-3xl p-8 shadow-2xl flex flex-col">
          <div className="mb-6">
            <h3 className="text-xl font-bold">Latency Trend</h3>
            <p className="text-xs text-zinc-500 mt-1">Avg. response time (ms)</p>
          </div>

          <div className="flex-1 min-h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={chartData}>
                <defs>
                  <linearGradient id="colorRT" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#028D86" stopOpacity={0.3}/>
                    <stop offset="95%" stopColor="#028D86" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#1e1e1e" />
                <XAxis dataKey="time" hide />
                <YAxis hide />
                <Tooltip
                  contentStyle={{ backgroundColor: '#121212', border: '1px solid #2d2d2d', borderRadius: '12px' }}
                  itemStyle={{ fontSize: '10px' }}
                />
                {sites.slice(0, 1).map((s) => (
                  <Area 
                    key={s.id}
                    type="monotone" 
                    dataKey={s.companyName} 
                    stroke="#028D86" 
                    strokeWidth={2}
                    fillOpacity={1} 
                    fill="url(#colorRT)" 
                  />
                ))}
              </AreaChart>
            </ResponsiveContainer>
          </div>

          <div className="mt-6 pt-6 border-t border-dark-800">
             <div className="flex justify-between items-center text-xs font-bold text-zinc-500 mb-4">
                <span>HEALTH SCORE</span>
                <span className="text-brand">99.2%</span>
             </div>
             <div className="w-full bg-dark-950 h-2 rounded-full overflow-hidden">
                <div className="bg-brand h-full w-[99.2%]"></div>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon, color, isActive, onClick }: { 
  title: string, 
  value: number, 
  icon: React.ReactNode, 
  color: string,
  isActive: boolean,
  onClick: () => void 
}) => {
  const colorMap: any = {
    brand: isActive ? 'border-brand ring-2 ring-brand/20 bg-brand/10' : 'hover:border-brand/50 bg-brand/5',
    emerald: isActive ? 'border-emerald-500 ring-2 ring-emerald-500/20 bg-emerald-500/10' : 'hover:border-emerald-500/50 bg-emerald-500/5',
    orange: isActive ? 'border-orange-500 ring-2 ring-orange-500/20 bg-orange-500/10' : 'hover:border-orange-500/50 bg-orange-500/5',
    rose: isActive ? 'border-rose-500 ring-2 ring-rose-500/20 bg-rose-500/10' : 'hover:border-rose-500/50 bg-rose-500/5',
  };

  return (
    <button 
      onClick={onClick}
      className={`text-left w-full border border-dark-800 rounded-3xl p-6 shadow-xl flex items-center justify-between group transition-all duration-300 ${colorMap[color]}`}
    >
      <div>
        <p className="text-xs text-zinc-500 font-bold uppercase tracking-wider">{title}</p>
        <p className="text-4xl font-black mt-2 tracking-tighter">{value}</p>
      </div>
      <div className={`p-4 rounded-2xl transition-transform shadow-inner ${isActive ? 'bg-dark-900 scale-110' : 'bg-dark-950 group-hover:scale-110'}`}>
        {icon}
      </div>
    </button>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { AppState, MonitoredSite } from '../types';
import StatusBar from '../components/StatusBar';
import { Globe, AlertTriangle, CheckCircle, XCircle } from '../components/Icons';

interface Props {
  state: AppState;
  onUpdate: (sites: MonitoredSite[]) => void;
}

type FilterStatus = 'all' | 'online' | 'warning' | 'offline';

const AllSites: React.FC<Props> = ({ state, onUpdate }) => {
  const navigate = useNavigate();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingSite, setEditingSite] = useState<MonitoredSite | null>(null);

  // Filtering states
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<FilterStatus>('all');

  const [formData, setFormData] = useState<Partial<MonitoredSite>>({
    companyName: '',
    url: '',
    interval: 5,
    timeout: 30,
    method: 'GET',
    statusRange: '200-399',
    keyword: ''
  });

  const filteredSites = useMemo(() => {
    return state.monitoredSites.filter(site => {
      const matchesSearch = site.companyName.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           site.url.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesStatus = statusFilter === 'all' || site.status === statusFilter;
      return matchesSearch && matchesStatus;
    });
  }, [state.monitoredSites, searchQuery, statusFilter]);

  const handleOpenAdd = () => {
    setEditingSite(null);
    setFormData({
      companyName: '',
      url: '',
      interval: 5,
      timeout: 30,
      method: 'GET',
      statusRange: '200-399',
      keyword: ''
    });
    setIsModalOpen(true);
  };

  const handleOpenEdit = (site: MonitoredSite) => {
    setEditingSite(site);
    setFormData(site);
    setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to delete this monitor?')) {
      onUpdate(state.monitoredSites.filter(s => s.id !== id));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingSite) {
      const updated = state.monitoredSites.map(s => s.id === editingSite.id ? { ...s, ...formData } as MonitoredSite : s);
      onUpdate(updated);
    } else {
      const newSite: MonitoredSite = {
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        status: 'online',
        responseTime: Array(24).fill(150),
        history: Array(30).fill('online'),
      } as MonitoredSite;
      onUpdate([...state.monitoredSites, newSite]);
    }
    setIsModalOpen(false);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-extrabold tracking-tight">Monitored Endpoints</h1>
          <p className="text-zinc-500 mt-1">Manage and configure your real-time 5-minute interval monitoring service.</p>
        </div>
        <button
          onClick={handleOpenAdd}
          className="bg-brand hover:bg-opacity-90 text-white px-8 py-4 rounded-2xl font-bold transition-all shadow-[0_10px_30px_rgba(2,141,134,0.3)] active:scale-95 shrink-0"
        >
          + Add New Monitor
        </button>
      </div>

      {/* Filters Bar */}
      <div className="flex flex-col md:flex-row gap-4 bg-dark-900/50 border border-dark-800 p-4 rounded-3xl shadow-lg">
         <div className="flex-1 relative">
            <input 
               type="text"
               placeholder="Search by name or URL..."
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
               className="w-full bg-dark-950 border border-dark-800 rounded-2xl py-3 px-5 pl-12 outline-none focus:ring-1 focus:ring-brand transition-all text-sm"
            />
            <Globe className="w-5 h-5 text-zinc-600 absolute left-4 top-1/2 -translate-y-1/2" />
         </div>
         <div className="flex gap-2">
            {(['all', 'online', 'warning', 'offline'] as FilterStatus[]).map((status) => (
              <button
                key={status}
                onClick={() => setStatusFilter(status)}
                className={`px-4 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest border transition-all ${
                  statusFilter === status 
                    ? 'bg-brand/10 border-brand text-brand' 
                    : 'bg-dark-950 border-dark-800 text-zinc-500 hover:border-dark-700'
                }`}
              >
                {status}
              </button>
            ))}
         </div>
      </div>

      <div className="grid gap-6">
        {filteredSites.map(site => (
          <div key={site.id} className="bg-dark-900 border border-dark-800 rounded-3xl p-8 hover:border-brand/40 transition-all flex flex-col lg:flex-row lg:items-center gap-10 shadow-xl group">
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-4 mb-2">
                <button 
                  onClick={() => navigate(`/sites/${site.id}`)}
                  className="w-14 h-14 bg-dark-950 border border-dark-800 rounded-2xl flex items-center justify-center font-black text-xl text-brand hover:border-brand transition-colors shadow-inner"
                >
                  {site.companyName.charAt(0).toUpperCase()}
                </button>
                <div>
                  <h3 className="font-extrabold text-2xl group-hover:text-brand transition-colors tracking-tight cursor-pointer" onClick={() => navigate(`/sites/${site.id}`)}>{site.companyName}</h3>
                  <div className="flex items-center gap-3 mt-1.5">
                    <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest border ${
                      site.status === 'online' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' : 
                      site.status === 'warning' ? 'bg-orange-500/10 text-orange-400 border-orange-500/20' : 
                      'bg-rose-500/10 text-rose-400 border-rose-500/20'
                    }`}>
                        {site.status}
                    </span>
                    <p className="text-zinc-600 text-sm font-mono truncate max-w-xs">{site.url}</p>
                  </div>
                </div>
              </div>

              <div className="mt-8">
                 <div className="flex justify-between items-center mb-3">
                    <span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest flex items-center gap-2">
                      <span className="w-1.5 h-1.5 rounded-full bg-brand animate-pulse"></span>
                      Real-time Uptime (5m Intervals)
                    </span>
                    <span className="text-[10px] font-bold text-zinc-600">LAST 2.5 HOURS</span>
                 </div>
                 <StatusBar history={site.history} isHighRes={true} />
              </div>
            </div>

            <div className="flex flex-col lg:items-end justify-center gap-4 lg:w-72 lg:border-l lg:border-dark-800 lg:pl-10 shrink-0">
              <div className="flex justify-between w-full lg:flex-col lg:items-end gap-1">
                <span className="text-[10px] text-zinc-500 font-black uppercase tracking-widest">Polling Interval</span>
                <span className="text-sm font-bold text-zinc-200">{site.interval} minutes</span>
              </div>
              <div className="flex justify-between w-full lg:flex-col lg:items-end gap-1">
                <span className="text-[10px] text-zinc-500 font-black uppercase tracking-widest">Avg Response</span>
                <span className="text-lg font-black text-brand">{(site.responseTime.reduce((a,b)=>a+b,0)/site.responseTime.length).toFixed(0)}ms</span>
              </div>
              <div className="flex flex-wrap gap-2 mt-4 w-full justify-end">
                <button 
                  onClick={() => navigate(`/sites/${site.id}`)}
                  className="flex-1 text-[10px] font-black uppercase tracking-widest text-white bg-brand hover:bg-opacity-90 px-3 py-2.5 rounded-xl transition-all"
                >
                  Profile
                </button>
                <button 
                  onClick={() => handleOpenEdit(site)} 
                  className="flex-1 text-[10px] font-black uppercase tracking-widest text-zinc-400 hover:text-white bg-dark-800 hover:bg-dark-700 px-3 py-2.5 rounded-xl transition-all"
                >
                  Edit
                </button>
                <button 
                  onClick={() => handleDelete(site.id)} 
                  className="flex-1 text-[10px] font-black uppercase tracking-widest text-rose-500 hover:text-rose-400 bg-rose-500/5 hover:bg-rose-500/10 px-3 py-2.5 rounded-xl transition-all"
                >
                  Delete
                </button>
              </div>
            </div>
          </div>
        ))}

        {filteredSites.length === 0 && (
          <div className="bg-dark-900 border border-dashed border-dark-800 rounded-3xl p-24 text-center">
            <Globe className="w-16 h-16 text-zinc-800 mx-auto mb-6" />
            <h3 className="text-2xl font-bold text-zinc-500">No matching monitors</h3>
            <p className="text-zinc-600 mt-2">Try adjusting your filters or search query.</p>
            <button 
              onClick={() => {setSearchQuery(''); setStatusFilter('all');}}
              className="mt-6 text-brand font-bold hover:underline"
            >
              Reset all filters
            </button>
          </div>
        )}
      </div>

      {/* Modal remains the same but with enhanced styling */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-md z-50 flex items-center justify-center p-4 animate-in fade-in duration-200">
          <div className="bg-dark-900 border border-dark-800 w-full max-w-xl rounded-[40px] p-12 shadow-2xl animate-in zoom-in-95 duration-200 overflow-hidden relative">
            <div className="absolute top-0 left-0 w-full h-2 bg-brand opacity-20"></div>
            <h2 className="text-3xl font-black mb-10 tracking-tight">{editingSite ? 'Modify Monitor' : 'New Monitor'}</h2>
            <form onSubmit={handleSubmit} className="space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Company Name</label>
                  <input
                    required
                    type="text"
                    value={formData.companyName}
                    onChange={e => setFormData({ ...formData, companyName: e.target.value })}
                    className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-brand/30 focus:border-brand outline-none transition-all font-medium"
                    placeholder="Acme Corp"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Endpoint URL</label>
                  <input
                    required
                    type="url"
                    value={formData.url}
                    onChange={e => setFormData({ ...formData, url: e.target.value })}
                    className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-brand/30 focus:border-brand outline-none transition-all font-medium"
                    placeholder="https://api.acme.com"
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-2">
                    <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Interval (min)</label>
                    <input
                        type="number"
                        min="1"
                        value={formData.interval}
                        onChange={e => setFormData({ ...formData, interval: Number(e.target.value) })}
                        className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-brand/30 focus:border-brand outline-none transition-all font-medium"
                    />
                </div>
                <div className="space-y-2">
                    <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Timeout (sec)</label>
                    <input
                        type="number"
                        value={formData.timeout}
                        onChange={e => setFormData({ ...formData, timeout: Number(e.target.value) })}
                        className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-brand/30 focus:border-brand outline-none transition-all font-medium"
                    />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-2">
                    <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Check Method</label>
                    <select
                        value={formData.method}
                        onChange={e => setFormData({ ...formData, method: e.target.value as any })}
                        className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-brand/30 focus:border-brand outline-none transition-all appearance-none font-medium"
                    >
                        <option value="GET">HTTP GET</option>
                        <option value="POST">HTTP POST</option>
                        <option value="HEAD">HTTP HEAD</option>
                    </select>
                </div>
                <div className="space-y-2">
                    <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Expected Status</label>
                    <input
                        type="text"
                        value={formData.statusRange}
                        onChange={e => setFormData({ ...formData, statusRange: e.target.value })}
                        className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-brand/30 focus:border-brand outline-none transition-all font-medium"
                        placeholder="200-399"
                    />
                </div>
              </div>

              <div className="flex gap-4 pt-10">
                <button
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="flex-1 px-8 py-5 rounded-[20px] border border-dark-800 text-zinc-500 font-black uppercase tracking-widest hover:bg-dark-800 hover:text-white transition-all text-xs"
                >
                  Discard
                </button>
                <button
                  type="submit"
                  className="flex-1 px-8 py-5 rounded-[20px] bg-brand text-white font-black uppercase tracking-widest hover:bg-opacity-90 transition-all shadow-xl text-xs"
                >
                  {editingSite ? 'Save Changes' : 'Create Monitor'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AllSites;

