import React, { useState } from 'react';
import { AppState, AppSettings, PublicSystem, Incident } from '../types';

interface Props {
  state: AppState;
  onUpdateSettings: (s: AppSettings) => void;
  onUpdatePublic: (p: PublicSystem[]) => void;
  onUpdateIncidents: (i: Incident[]) => void;
}

const Settings: React.FC<Props> = ({ state, onUpdateSettings, onUpdatePublic, onUpdateIncidents }) => {
  const [webhook, setWebhook] = useState(state.settings.discordWebhook);
  const [isSaved, setIsSaved] = useState(false);

  // States for Incident Form including time
  const [newIncident, setNewIncident] = useState({ 
    title: '', 
    description: '', 
    date: new Date().toISOString().split('T')[0],
    time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) 
  });

  const handleSaveDiscord = () => {
    onUpdateSettings({ ...state.settings, discordWebhook: webhook });
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 2000);
  };

  const togglePublicStatus = (id: string) => {
      const nextStatus = (status: string) => {
          if (status === 'operational') return 'partial';
          if (status === 'partial') return 'down';
          return 'operational';
      };

      const updated = state.publicSystems.map(s => {
          if (s.id === id) {
              const newStat = nextStatus(s.status) as any;
              // SYNC: Update the last bar in history to match current status instantly
              const newHistory = [...s.history];
              if (newHistory.length > 0) {
                  newHistory[newHistory.length - 1] = newStat;
              }
              return { ...s, status: newStat, history: newHistory };
          }
          return s;
      });
      onUpdatePublic(updated);
  };

  const handleAddIncident = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newIncident.title || !newIncident.description) return;
    const incident: Incident = {
        id: Math.random().toString(36).substr(2, 9),
        ...newIncident
    };
    onUpdateIncidents([...state.incidents, incident]);
    setNewIncident({ 
        title: '', 
        description: '', 
        date: new Date().toISOString().split('T')[0],
        time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) 
    });
  };

  const handleDeleteIncident = (id: string) => {
    if (confirm('Are you sure?')) {
        onUpdateIncidents(state.incidents.filter(i => i.id !== id));
    }
  };

  return (
    <div className="space-y-10">
      <div>
        <h1 className="text-2xl font-bold">Settings</h1>
        <p className="text-zinc-500">Global configuration and notification preferences.</p>
      </div>

      {/* Discord Section */}
      <section className="bg-dark-900 border border-dark-800 rounded-2xl p-8 shadow-xl">
        <div className="flex items-center gap-3 mb-6">
            <div className="p-2 bg-[#5865F2]/10 rounded-lg">
                <svg className="w-6 h-6 text-[#5865F2]" fill="currentColor" viewBox="0 0 24 24"><path d="M20.317 4.37a19.791 19.791 0 0 0-4.885-1.515.074.074 0 0 0-.079.037c-.21.375-.444.864-.608 1.25a18.27 18.27 0 0 0-5.487 0 12.64 12.64 0 0 0-.617-1.25.077.077 0 0 0-.079-.037A19.736 19.736 0 0 0 3.677 4.37a.07.07 0 0 0-.032.027C.533 9.046-.32 13.58.099 18.057a.082.082 0 0 0 .031.057 19.9 19.9 0 0 0 5.993 3.03.078.078 0 0 0 .084-.028c.462-.63.874-1.295 1.226-1.994.021-.041.001-.09-.041-.106a13.107 13.107 0 0 1-1.872-.892.077.077 0 0 1-.008-.128 10.23 10.23 0 0 0 .372-.292.074.074 0 0 1 .077-.01c3.928 1.793 8.18 1.793 12.062 0a.074.074 0 0 1 .078.01c.12.098.246.198.373.292a.077.077 0 0 1-.006.127 12.299 12.299 0 0 1-1.873.892.077.077 0 0 0-.041.107c.36.698.772 1.362 1.225 1.993.023.03.063.04.085.029a19.839 19.839 0 0 0 6.002-3.03.077.077 0 0 0 .032-.057c.403-5.136-1.011-9.573-4.052-13.657a.06.06 0 0 0-.033-.028zM8.02 15.33c-1.183 0-2.157-1.085-2.157-2.419 0-1.333.955-2.419 2.157-2.419 1.21 0 2.176 1.096 2.157 2.42 0 1.333-.956 2.418-2.157 2.418zm7.975 0c-1.183 0-2.157-1.085-2.157-2.419 0-1.333.955-2.419 2.157-2.419 1.21 0 2.176 1.096 2.157 2.42 0 1.333-.946 2.418-2.157 2.418z"/></svg>
            </div>
            <h2 className="text-xl font-bold">Discord Integration</h2>
        </div>
        <div className="space-y-4">
          <div className="space-y-2">
            <label className="text-sm text-zinc-400">Webhook URL</label>
            <input
