                    <div>
                        <p className="font-semibold text-sm">{system.name}</p>
                        <p className={`text-[10px] font-bold uppercase tracking-widest mt-1 ${system.status === 'operational' ? 'text-emerald-500' : system.status === 'partial' ? 'text-orange-500' : 'text-rose-500'}`}>
                            {system.status}
                        </p>
                    </div>
                    <button
                        onClick={() => togglePublicStatus(system.id)}
                        className="text-xs font-bold text-zinc-400 hover:text-white bg-dark-800 hover:bg-dark-700 px-3 py-1.5 rounded-lg transition-colors"
                    >
                        Cycle Status
                    </button>
                </div>
            ))}
        </div>
      </section>

      {/* Incident History Management */}
      <section className="bg-dark-900 border border-dark-800 rounded-2xl p-8 shadow-xl">
        <h2 className="text-xl font-bold mb-2">Incident History Management</h2>
        <p className="text-zinc-500 text-sm mb-8">Add or remove incidents that will be displayed publicly.</p>

        <form onSubmit={handleAddIncident} className="space-y-4 mb-10 bg-dark-950/50 p-6 rounded-xl border border-dark-800">
            <h3 className="text-sm font-bold uppercase tracking-widest text-zinc-400 mb-4">Add New Incident</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="space-y-1">
                    <label className="text-xs text-zinc-500 font-bold uppercase">Title</label>
                    <input
                        required
                        type="text"
                        value={newIncident.title}
                        onChange={e => setNewIncident({...newIncident, title: e.target.value})}
                        className="w-full bg-dark-900 border border-dark-800 rounded-xl px-4 py-2 outline-none focus:ring-1 focus:ring-brand"
                        placeholder="e.g. Email Delivery Issues"
                    />
                </div>
                <div className="space-y-1">
                    <label className="text-xs text-zinc-500 font-bold uppercase">Date</label>
                    <input
                        required
                        type="date"
                        value={newIncident.date}
                        onChange={e => setNewIncident({...newIncident, date: e.target.value})}
                        className="w-full bg-dark-900 border border-dark-800 rounded-xl px-4 py-2 outline-none focus:ring-1 focus:ring-brand"
                    />
                </div>
                <div className="space-y-1">
                    <label className="text-xs text-zinc-500 font-bold uppercase">Time</label>
                    <input
                        required
                        type="time"
                        value={newIncident.time}
                        onChange={e => setNewIncident({...newIncident, time: e.target.value})}
                        className="w-full bg-dark-900 border border-dark-800 rounded-xl px-4 py-2 outline-none focus:ring-1 focus:ring-brand"
                    />
                </div>
            </div>
            <div className="space-y-1">
                <label className="text-xs text-zinc-500 font-bold uppercase">Description</label>
                <textarea
                    required
                    value={newIncident.description}
                    onChange={e => setNewIncident({...newIncident, description: e.target.value})}
                    className="w-full bg-dark-900 border border-dark-800 rounded-xl px-4 py-2 outline-none focus:ring-1 focus:ring-brand min-h-[100px]"
                    placeholder="Incident details and mitigation steps..."
                ></textarea>
            </div>
            <button type="submit" className="bg-emerald-600 hover:bg-emerald-500 text-white font-bold py-2 px-6 rounded-xl transition-all">
                Add Incident
            </button>
        </form>

        <div className="space-y-4">
            <h3 className="text-sm font-bold uppercase tracking-widest text-zinc-400">Incident List</h3>
            {state.incidents.length > 0 ? (
                [...state.incidents].reverse().map(incident => (
                    <div key={incident.id} className="flex items-center justify-between p-4 bg-dark-950 border border-dark-800 rounded-xl">
                        <div>
                            <p className="font-bold text-sm">{incident.title}</p>
                            <p className="text-xs text-zinc-500 font-mono">
                                {incident.date} <span className="text-brand font-bold ml-2">{incident.time}</span>
                            </p>
                        </div>
                        <button
                            onClick={() => handleDeleteIncident(incident.id)}
                            className="text-rose-500 hover:text-rose-400 text-xs font-bold"
                        >
                            Delete
                        </button>
                    </div>
                ))
            ) : (
                <p className="text-zinc-600 italic text-sm">No incidents recorded.</p>
            )}
        </div>
      </section>
    </div>
  );
};

export default Settings;

import React, { useMemo, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { AppState, MonitoredSite } from '../types';
import StatusBar from '../components/StatusBar';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';
import { CheckCircle, AlertTriangle, XCircle, Globe, Shield } from '../components/Icons';

interface Props {
  state: AppState;
  onUpdateSites: (sites: MonitoredSite[]) => void;
}

const SiteProfile: React.FC<Props> = ({ state, onUpdateSites }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [isChecking, setIsChecking] = useState(false);

  const site = useMemo(() => {
    return state.monitoredSites.find(s => s.id === id);
  }, [state.monitoredSites, id]);

  if (!site) {
    return (
      <div className="flex flex-col items-center justify-center h-full py-24 bg-dark-950 rounded-[40px] border border-dark-800">
        <Globe className="w-16 h-16 text-zinc-700 mb-6" />
        <h2 className="text-2xl font-black text-white">Monitor Not Found</h2>
        <p className="text-zinc-500 mt-2">The site you are looking for does not exist or has been removed.</p>
        <button 
          onClick={() => navigate('/sites')}
          className="mt-8 px-8 py-4 bg-brand text-white font-black uppercase tracking-widest rounded-2xl hover:bg-opacity-90 transition-all"
        >
          Return to List
        </button>
      </div>
    );
  }

  const chartData = site.responseTime.map((val, idx) => ({
    time: `${idx}:00`,
    latency: val
  }));

  const avgLatency = (site.responseTime.reduce((a, b) => a + b, 0) / site.responseTime.length).toFixed(0);
  const maxLatency = Math.max(...site.responseTime);
  const minLatency = Math.min(...site.responseTime);

  const handleDelete = () => {
    if (confirm(`Are you sure you want to delete ${site.companyName}?`)) {
      onUpdateSites(state.monitoredSites.filter(s => s.id !== site.id));
      navigate('/sites');
    }
  };

  const handleForceCheck = async () => {
    if (isChecking) return;
    setIsChecking(true);

    // Simulate network delay
    await new Promise(resolve => setTimeout(resolve, 1500));

    const newRT = Math.floor(Math.random() * 150) + 40; // Simulated response time
    const statuses: ('online' | 'offline' | 'warning')[] = ['online', 'online', 'online', 'warning'];
    const newStatus = statuses[Math.floor(Math.random() * statuses.length)];

    const updatedSites = state.monitoredSites.map(s => {
      if (s.id === site.id) {
        const nextResponseTimes = [...s.responseTime];
        nextResponseTimes[nextResponseTimes.length - 1] = newRT;

        const nextHistory = [...s.history];
        nextHistory[nextHistory.length - 1] = newStatus;

        return {
          ...s,
          status: newStatus,
          responseTime: nextResponseTimes,
          history: nextHistory,
          lastChecked: new Date().toLocaleTimeString()
        };
      }
      return s;
    });

    onUpdateSites(updatedSites);
    setIsChecking(false);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Profile Header */}
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-8 bg-dark-900 border border-dark-800 p-8 md:p-12 rounded-[40px] shadow-2xl overflow-hidden relative group">
        <div className="absolute top-0 right-0 w-64 h-64 bg-brand opacity-[0.03] blur-3xl pointer-events-none -translate-y-1/2 translate-x-1/2"></div>

        <div className="flex items-start gap-6 flex-1 min-w-0">
          <div className="w-20 h-20 bg-dark-950 border border-dark-800 rounded-[28px] flex items-center justify-center font-black text-3xl text-brand shrink-0 shadow-inner group-hover:border-brand/40 transition-all">
            {site.companyName.charAt(0).toUpperCase()}
          </div>
          <div className="min-w-0">
            <h1 className="text-4xl md:text-5xl font-black tracking-tighter text-white truncate">{site.companyName}</h1>
            <div className="flex flex-wrap items-center gap-4 mt-3">
              <a 
                href={site.url} 
                target="_blank" 
                rel="noopener noreferrer" 
                className="text-brand font-mono text-sm hover:underline flex items-center gap-2"
              >
                {site.url}
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" /></svg>
              </a>
              <span className={`px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest border shadow-sm ${
                site.status === 'online' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' : 
                site.status === 'warning' ? 'bg-orange-500/10 text-orange-400 border-orange-500/20' : 
                'bg-rose-500/10 text-rose-400 border-rose-500/20'
              }`}>
                {site.status}
              </span>
            </div>
          </div>
        </div>

        <div className="flex flex-wrap gap-4 shrink-0">
            <button 
                onClick={handleDelete}
                className="px-6 py-4 bg-rose-500/5 hover:bg-rose-500/10 text-rose-500 border border-rose-500/20 rounded-2xl text-xs font-black uppercase tracking-widest transition-all"
            >
                Remove Monitor
            </button>
            <button 
                onClick={() => navigate('/sites')}
                className="px-6 py-4 bg-dark-950 hover:bg-dark-800 text-zinc-400 hover:text-white border border-dark-800 rounded-2xl text-xs font-black uppercase tracking-widest transition-all"
            >
                Back to Sites
            </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column: Latency Detail */}
        <div className="lg:col-span-2 space-y-8">
            {/* Latency Chart */}
            <div className="bg-dark-900 border border-dark-800 rounded-[40px] p-8 md:p-10 shadow-2xl">
                <div className="flex items-center justify-between mb-10">
                    <div>
                        <h3 className="text-2xl font-black tracking-tight">Performance Trend</h3>
                        <p className="text-sm text-zinc-500 mt-1">Response time analysis over the last 24 checkpoints</p>
                    </div>
                    <div className="flex gap-4">
                        <div className="text-right">
                            <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Average</p>
                            <p className="text-xl font-black text-brand">{avgLatency}ms</p>
                        </div>
                        <div className="text-right border-l border-dark-800 pl-4">
                            <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Max</p>
                            <p className="text-xl font-black text-white">{maxLatency}ms</p>
                        </div>
                    </div>
                </div>

                <div className="h-[400px] w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <AreaChart data={chartData}>
                            <defs>
                                <linearGradient id="profileRT" x1="0" y1="0" x2="0" y2="1">
                                    <stop offset="5%" stopColor="#028D86" stopOpacity={0.4}/>
                                    <stop offset="95%" stopColor="#028D86" stopOpacity={0}/>
                                </linearGradient>
                            </defs>
                            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#1e1e1e" />
                            <XAxis 
                                dataKey="time" 
                                stroke="#52525b" 
                                fontSize={10} 
                                tickLine={false} 
                                axisLine={false} 
                                dy={10}
                                tick={{ fontWeight: 'bold' }}
                            />
                            <YAxis 
                                stroke="#52525b" 
                                fontSize={10} 
                                tickLine={false} 
                                axisLine={false} 
                                tickFormatter={(val) => `${val}ms`}
                                tick={{ fontWeight: 'bold' }}
                            />
                            <Tooltip
                                contentStyle={{ 
                                    backgroundColor: '#0a0a0a', 
                                    border: '1px solid #1e1e1e', 
                                    borderRadius: '20px', 
                                    boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.5)',
                                    padding: '12px 16px'
                                }}
                                itemStyle={{ fontSize: '12px', fontWeight: '900', color: '#028D86' }}
                                labelStyle={{ color: '#71717a', fontSize: '10px', marginBottom: '4px', fontWeight: 'bold' }}
                                labelFormatter={(label) => `Checkpoint: ${label}`}
                            />
                            <Area 
                                type="monotone" 
                                dataKey="latency" 
                                stroke="#028D86" 
                                strokeWidth={4}
                                fillOpacity={1} 
                                fill="url(#profileRT)" 
                                animationDuration={1500}
                            />
                        </AreaChart>
                    </ResponsiveContainer>
                </div>
            </div>

            {/* Detailed Uptime History */}
            <div className="bg-dark-900 border border-dark-800 rounded-[40px] p-8 md:p-10 shadow-2xl">
                <div className="flex items-center justify-between mb-8">
                    <h3 className="text-2xl font-black tracking-tight">Availability Log</h3>
                    <div className="flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-emerald-500"></span>
                        <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">99.98% Lifetime Uptime</span>
                    </div>
                </div>

                <div className="space-y-6">
                    <div>
                        <p className="text-xs font-black text-zinc-600 uppercase tracking-widest mb-4">Historical Status (5m Interval High-Res)</p>
                        <StatusBar history={site.history} isHighRes={true} />
                        <div className="flex justify-between mt-4 text-[9px] font-black text-zinc-700 uppercase tracking-[0.2em]">
                            <span>2.5 Hours Ago</span>
                            <span>Currently Live</span>
                        </div>
                    </div>

                    <div className="pt-8 border-t border-dark-800">
                        <p className="text-xs font-black text-zinc-600 uppercase tracking-widest mb-6">Recent Events</p>
                        <div className="space-y-4">
                            <EventItem time="Just now" type="CHECK" msg={`Successfully completed health check`} latency={`${site.responseTime[site.responseTime.length - 1]}ms`} />
                            <EventItem time="5 mins ago" type="CHECK" msg="Successfully completed 200 OK check" latency={`${site.responseTime[22]}ms`} />
                            {site.status === 'offline' && (
                                <EventItem time="10 mins ago" type="FAILURE" msg="Timeout reached: Connection refused" color="text-rose-500" />
                            )}
                            <EventItem time="15 mins ago" type="CHECK" msg="Successfully completed 200 OK check" latency={`${site.responseTime[21]}ms`} />
                        </div>
                    </div>
                </div>
            </div>
        </div>

        {/* Right Column: Configuration & Meta */}
        <div className="space-y-8">
            {/* Monitor Specs */}
            <div className="bg-dark-900 border border-dark-800 rounded-[40px] p-8 md:p-10 shadow-2xl">
                <h3 className="text-xl font-black tracking-tight mb-8">Monitor Profile</h3>

                <div className="space-y-6">
                    <SpecItem label="Monitor ID" value={site.id} mono />
                    <SpecItem label="Check Frequency" value={`Every ${site.interval} Minutes`} />
                    <SpecItem label="Request Method" value={site.method} />
                    <SpecItem label="Expected Status" value={site.statusRange} />
                    <SpecItem label="Timeout Threshold" value={`${site.timeout} Seconds`} />
                    <SpecItem label="Keyword Check" value={site.keyword || 'None configured'} />
                    <SpecItem label="Last Verified" value={site.lastChecked || new Date().toLocaleTimeString()} />
                </div>

                <button 
                  disabled={isChecking}
                  onClick={handleForceCheck}
                  className={`w-full mt-10 py-4 bg-dark-950 border border-dark-800 hover:border-brand/40 text-white text-xs font-black uppercase tracking-widest rounded-2xl transition-all flex items-center justify-center gap-3 shadow-lg group ${isChecking ? 'opacity-50 cursor-not-allowed' : ''}`}
                >
                    <div className={`w-2 h-2 rounded-full bg-brand ${isChecking ? 'animate-ping' : 'group-hover:animate-pulse'}`}></div>
                    {isChecking ? 'Verifying...' : 'Force Check Now'}
                </button>
            </div>

            {/* Notification Card */}
            <div className="bg-brand rounded-[40px] p-8 md:p-10 shadow-2xl text-white relative overflow-hidden group">
                <div className="absolute top-0 left-0 w-full h-full bg-black/10 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
                <div className="relative z-10">
                    <div className="p-3 bg-white/20 w-fit rounded-2xl mb-6">
                        <AlertTriangle className="w-6 h-6 text-white" />
                    </div>
                    <h4 className="text-xl font-black tracking-tight">Alert Preferences</h4>
                    <p className="text-sm text-white/70 mt-2 mb-8 leading-relaxed">Notifications for this monitor are routed via the global Discord Webhook integration.</p>

                    <button 
                      onClick={() => navigate('/settings')}
                      className="w-full py-4 bg-white text-brand font-black uppercase tracking-widest rounded-2xl text-xs shadow-xl hover:scale-105 active:scale-95 transition-all"
                    >
                        Configure Alerts
                    </button>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

const SpecItem = ({ label, value, mono = false }: { label: string, value: string, mono?: boolean }) => (
    <div className="flex flex-col gap-1">
        <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">{label}</span>
        <span className={`text-sm font-bold text-zinc-200 ${mono ? 'font-mono' : ''}`}>{value}</span>
    </div>
);

const EventItem = ({ time, type, msg, latency, color = "text-emerald-500" }: { time: string, type: string, msg: string, latency?: string, color?: string }) => (
    <div className="flex items-start gap-4 p-4 bg-dark-950 border border-dark-800 rounded-2xl shadow-sm">
        <div className="flex flex-col items-center shrink-0 w-12 pt-1">
            <span className="text-[9px] font-black text-zinc-600 uppercase tracking-tighter">{time}</span>
        </div>
        <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2 mb-0.5">
                <span className={`text-[10px] font-black uppercase tracking-widest ${color}`}>{type}</span>
                {latency && <span className="text-[10px] font-mono text-zinc-600">{latency}</span>}
            </div>
            <p className="text-xs text-zinc-400 font-medium truncate">{msg}</p>
        </div>
    </div>
);

