import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { AppState, MonitoredSite } from '../types';
import { CheckCircle, AlertTriangle, XCircle, Globe, Shield } from '../components/Icons';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';

interface Props {
  state: AppState;
}

type FilterType = 'all' | 'online' | 'warning' | 'offline';

const Dashboard: React.FC<Props> = ({ state }) => {
  const navigate = useNavigate();
  const [activeFilter, setActiveFilter] = useState<FilterType>('all');

  // Quick Check States
  const [quickCheckUrl, setQuickCheckUrl] = useState('');
  const [isChecking, setIsChecking] = useState(false);
  const [checkResult, setCheckResult] = useState<{ status: 'online' | 'offline', rt: number, url: string } | null>(null);

  const sites = state.monitoredSites;

  const total = sites.length;
  const operationalCount = sites.filter(s => s.status === 'online').length;
  const warningsCount = sites.filter(s => s.status === 'warning').length;
  const downtimeCount = sites.filter(s => s.status === 'offline').length;

  const filteredSites = useMemo(() => {
    if (activeFilter === 'all') return sites;
    return sites.filter(s => s.status === activeFilter);
  }, [sites, activeFilter]);

  // Aggregate response time data for the chart
  const chartData = sites.length > 0 ? sites[0].responseTime.map((val, idx) => {
    const point: any = { time: `${idx}:00` };
    sites.slice(0, 3).forEach(s => {
      point[s.companyName] = s.responseTime[idx];
    });
    return point;
  }) : [];

  const handleQuickCheck = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!quickCheckUrl) return;

    setIsChecking(true);
    // Simulate real network delay
    await new Promise(resolve => setTimeout(resolve, 1800));

    const isOnline = Math.random() > 0.1; // 90% chance online
    const rt = isOnline ? Math.floor(Math.random() * 300) + 50 : 0;

    setCheckResult({
      status: isOnline ? 'online' : 'offline',
      rt: rt,
      url: quickCheckUrl
    });
    setIsChecking(false);
    setQuickCheckUrl('');
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-3xl font-extrabold tracking-tight">System Overview</h1>
          <p className="text-zinc-500 mt-1">Real-time infrastructure health and performance metrics.</p>
        </div>
        <div className="flex items-center gap-3 bg-dark-900/50 border border-dark-800 px-5 py-2.5 rounded-2xl text-xs font-bold text-brand shadow-lg">
           <span className="relative flex h-2 w-2">
             <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-brand opacity-75"></span>
             <span className="relative inline-flex rounded-full h-2 w-2 bg-brand"></span>
           </span>
           LIVE MONITORING ACTIVE
        </div>
      </div>

      {/* Stats Cards with Filtering */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          title="Total Monitors" 
          value={total} 
          icon={<Globe className="w-6 h-6 text-brand" />} 
          color="brand" 
          isActive={activeFilter === 'all'}
          onClick={() => setActiveFilter('all')}
        />
        <StatCard 
          title="Operational" 
          value={operationalCount} 
          icon={<CheckCircle className="w-6 h-6 text-emerald-500" />} 
          color="emerald" 
          isActive={activeFilter === 'online'}
          onClick={() => setActiveFilter('online')}
        />
        <StatCard 
          title="Warnings" 
          value={warningsCount} 
          icon={<AlertTriangle className="w-6 h-6 text-orange-500" />} 
          color="orange" 
          isActive={activeFilter === 'warning'}
          onClick={() => setActiveFilter('warning')}
        />
        <StatCard 
          title="Downtime" 
          value={downtimeCount} 
          icon={<XCircle className="w-6 h-6 text-rose-500" />} 
          color="rose" 
          isActive={activeFilter === 'offline'}
          onClick={() => setActiveFilter('offline')}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Section (2/3) */}
        <div className="lg:col-span-2 space-y-8">
            {/* Live Status Feed */}
            <div className="bg-dark-900 border border-dark-800 rounded-3xl p-8 shadow-2xl">
                <div className="flex items-center justify-between mb-8">
                  <div>
                    <h3 className="text-2xl font-black tracking-tight">Live Status Feed</h3>
                    <p className="text-sm text-zinc-500 mt-1">
                      Showing {activeFilter === 'all' ? 'all' : activeFilter} monitors ({filteredSites.length})
                    </p>
                  </div>
                  {activeFilter !== 'all' && (
                    <button 
                      onClick={() => setActiveFilter('all')}
                      className="text-xs font-bold text-brand hover:underline"
                    >
                      Clear Filter
                    </button>
                  )}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-[600px] overflow-y-auto custom-scrollbar pr-2">
                    {filteredSites.map(site => (
                        <button 
                          key={site.id} 
                          onClick={() => navigate(`/sites/${site.id}`)}
                          className="flex items-center justify-between p-5 rounded-2xl bg-dark-950 border border-dark-800 hover:border-brand/40 transition-all group shadow-sm text-left w-full"
                        >
                            <div className="min-w-0 flex-1 mr-4">
                                <div className="flex items-center gap-2 mb-1">
