}

import React, { useState } from 'react';
import { AppState, PublicSystem, Incident, StatusType } from '../types';

interface Props {
  state: AppState;
  onUpdatePublic: (p: PublicSystem[]) => void;
  onUpdateIncidents: (i: Incident[]) => void;
}

const PublicManagement: React.FC<Props> = ({ state, onUpdatePublic, onUpdateIncidents }) => {
  const [newIncident, setNewIncident] = useState({ 
    title: '', 
    description: '', 
    date: new Date().toISOString().split('T')[0],
    time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
    systemId: state.publicSystems[0]?.id || '',
    impactStatus: 'down' as StatusType
  });

  const togglePublicStatus = (id: string) => {
      const nextStatus = (status: string) => {
          if (status === 'operational') return 'partial';
          if (status === 'partial') return 'down';
          return 'operational';
      };

      const updated = state.publicSystems.map(s => {
          if (s.id === id) {
              const newStat = nextStatus(s.status) as any;
              const newHistory = [...s.history];
              if (newHistory.length > 0) {
                  newHistory[newHistory.length - 1] = newStat;
              }
              return { ...s, status: newStat, history: newHistory };
          }
          return s;
      });
      onUpdatePublic(updated);
  };

  const updateSystemStatus = (systemId: string, status: StatusType) => {
    const updated = state.publicSystems.map(s => {
      if (s.id === systemId) {
        const newHistory = [...s.history];
        if (newHistory.length > 0) {
          newHistory[newHistory.length - 1] = status;
        }
        return { ...s, status, history: newHistory };
      }
      return s;
    });
    onUpdatePublic(updated);
  };

  const handleAddIncident = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newIncident.title || !newIncident.description || !newIncident.systemId) return;

    const incident: Incident = {
        id: Math.random().toString(36).substr(2, 9),
        ...newIncident,
        status: 'active'
    };

    // Update the incident list
    onUpdateIncidents([...state.incidents, incident]);

    // Update the system status automatically based on the incident impact
    updateSystemStatus(newIncident.systemId, newIncident.impactStatus);

    // Reset form
    setNewIncident({ 
        title: '', 
        description: '', 
        date: new Date().toISOString().split('T')[0],
        time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        systemId: state.publicSystems[0]?.id || '',
        impactStatus: 'down'
    });
  };

  const handleResolveIncident = (id: string) => {
    const incidentToResolve = state.incidents.find(inc => inc.id === id);
    if (!incidentToResolve) return;

    const updatedIncidents = state.incidents.map(inc => 
      inc.id === id ? { ...inc, status: 'resolved' as const } : inc
    );

    onUpdateIncidents(updatedIncidents);

    // After resolving, check if there are other active incidents for this system
    const systemId = incidentToResolve.systemId;
    const otherActiveIncidents = updatedIncidents.filter(inc => inc.systemId === systemId && inc.status === 'active');

    if (otherActiveIncidents.length === 0) {
      // No more active incidents, set system back to operational
      updateSystemStatus(systemId, 'operational');
    } else {
      // Find the "worst" impact status among remaining active incidents
      const priority: Record<StatusType, number> = { 'down': 3, 'partial': 2, 'operational': 1 };
      const worstStatus = otherActiveIncidents.reduce((prev, curr) => {
        return (priority[curr.impactStatus] > priority[prev]) ? curr.impactStatus : prev;
      }, 'operational' as StatusType);

      updateSystemStatus(systemId, worstStatus);
    }
  };

  const handleDeleteIncident = (id: string) => {
    if (confirm('Are you sure you want to delete this incident permanently?')) {
        onUpdateIncidents(state.incidents.filter(i => i.id !== id));
    }
  };

  return (
    <div className="space-y-10 animate-in fade-in duration-500">
      <div>
        <h1 className="text-3xl font-black tracking-tight">Public Status Management</h1>
        <p className="text-zinc-500 mt-1">Control how your services are displayed on the public status page.</p>
      </div>

      {/* Manual Public Status Section */}
      <section className="bg-dark-900 border border-dark-800 rounded-3xl p-8 shadow-xl">
        <div className="flex items-center justify-between mb-8">
            <div>
                <h2 className="text-xl font-bold mb-2">System Health Control</h2>
                <p className="text-zinc-500 text-sm">Manually override service status. Note: Active incidents may override this.</p>
            </div>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {state.publicSystems.map(system => {
                const hasActiveIncident = state.incidents.some(inc => inc.systemId === system.id && inc.status === 'active');
                return (
                    <div key={system.id} className={`p-6 bg-dark-950 border rounded-2xl flex flex-col gap-4 group transition-all ${hasActiveIncident ? 'border-brand/40 shadow-[0_0_20px_rgba(2,141,134,0.1)]' : 'border-dark-800'}`}>
                        <div className="flex items-center justify-between">
                            <div className="flex flex-col">
                                <p className="font-bold text-base text-zinc-100">{system.name}</p>
                                {hasActiveIncident && (
                                    <span className="text-[9px] font-black text-brand uppercase tracking-tighter">Active Incident Linked</span>
                                )}
                            </div>
                            <div className={`w-3 h-3 rounded-full ${system.status === 'operational' ? 'bg-emerald-500' : system.status === 'partial' ? 'bg-orange-500' : 'bg-rose-500'} animate-pulse`}></div>
                        </div>
                        <div className="flex items-center justify-between">
                            <p className={`text-[10px] font-black uppercase tracking-widest ${system.status === 'operational' ? 'text-emerald-500' : system.status === 'partial' ? 'text-orange-500' : 'text-rose-500'}`}>
                                {system.status}
                            </p>
                            <button
                                onClick={() => togglePublicStatus(system.id)}
                                className="text-xs font-black uppercase tracking-tighter text-zinc-400 hover:text-white bg-dark-800 hover:bg-dark-700 px-4 py-2 rounded-xl transition-all"
                            >
                                Cycle Status
                            </button>
                        </div>
                    </div>
                );
            })}
        </div>
      </section>

      {/* Incident History Management */}
      <section className="bg-dark-900 border border-dark-800 rounded-3xl p-8 shadow-xl">
        <h2 className="text-xl font-bold mb-2">Incident Log Manager</h2>
        <p className="text-zinc-500 text-sm mb-10">Add official service disruption records. Setting a status will update the public board.</p>

        <form onSubmit={handleAddIncident} className="space-y-6 mb-12 bg-dark-950 p-8 rounded-3xl border border-dark-800 shadow-inner">
            <h3 className="text-sm font-black uppercase tracking-widest text-brand mb-6 flex items-center gap-2">
                <span className="w-2 h-2 rounded-full bg-brand"></span>
                Record New Incident
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="space-y-1">
                    <label className="text-[10px] text-zinc-500 font-black uppercase tracking-widest ml-1">Event Title</label>
                    <input
                        required
                        type="text"
                        value={newIncident.title}
                        onChange={e => setNewIncident({...newIncident, title: e.target.value})}
                        className="w-full bg-dark-900 border border-dark-800 rounded-2xl px-5 py-3 outline-none focus:ring-1 focus:ring-brand font-bold text-sm"
                        placeholder="e.g. Major Server Outage"
                    />
                </div>
                <div className="space-y-1">
                    <label className="text-[10px] text-zinc-500 font-black uppercase tracking-widest ml-1">Affected System</label>
                    <select
                        required
                        value={newIncident.systemId}
                        onChange={e => setNewIncident({...newIncident, systemId: e.target.value})}
                        className="w-full bg-dark-900 border border-dark-800 rounded-2xl px-5 py-3 outline-none focus:ring-1 focus:ring-brand font-bold text-sm appearance-none"
                    >
                        {state.publicSystems.map(s => (
                            <option key={s.id} value={s.id}>{s.name}</option>
                        ))}
                    </select>
                </div>
                <div className="space-y-1">
                    <label className="text-[10px] text-zinc-500 font-black uppercase tracking-widest ml-1">Incident Severity (Status)</label>
                    <select
                        required
                        value={newIncident.impactStatus}
                        onChange={e => setNewIncident({...newIncident, impactStatus: e.target.value as StatusType})}
                        className={`w-full bg-dark-900 border border-dark-800 rounded-2xl px-5 py-3 outline-none focus:ring-1 focus:ring-brand font-bold text-sm appearance-none ${
                            newIncident.impactStatus === 'down' ? 'text-rose-500' : newIncident.impactStatus === 'partial' ? 'text-orange-500' : 'text-emerald-500'
                        }`}
                    >
                        <option value="operational">Operational (Info Only)</option>
                        <option value="partial">Partial Issues (Warning)</option>
                        <option value="down">System Down (Critical)</option>
                    </select>
                </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-1">
                    <label className="text-[10px] text-zinc-500 font-black uppercase tracking-widest ml-1">Occurrence Date</label>
                    <input
                        required
                        type="date"
                        value={newIncident.date}
                        onChange={e => setNewIncident({...newIncident, date: e.target.value})}
                        className="w-full bg-dark-900 border border-dark-800 rounded-2xl px-5 py-3 outline-none focus:ring-1 focus:ring-brand font-bold text-sm"
                    />
                </div>
                <div className="space-y-1">
                    <label className="text-[10px] text-zinc-500 font-black uppercase tracking-widest ml-1">Arrival Time</label>
                    <input
                        required
                        type="time"
                        value={newIncident.time}
                        onChange={e => setNewIncident({...newIncident, time: e.target.value})}
                        className="w-full bg-dark-900 border border-dark-800 rounded-2xl px-5 py-3 outline-none focus:ring-1 focus:ring-brand font-bold text-sm"
                    />
                </div>
            </div>
            <div className="space-y-1">
                <label className="text-[10px] text-zinc-500 font-black uppercase tracking-widest ml-1">Description & Mitigation</label>
                <textarea
                    required
                    value={newIncident.description}
                    onChange={e => setNewIncident({...newIncident, description: e.target.value})}
                    className="w-full bg-dark-900 border border-dark-800 rounded-2xl px-5 py-3 outline-none focus:ring-1 focus:ring-brand min-h-[120px] text-sm font-medium"
                    placeholder="Provide details about the issue and any steps taken to resolve it..."
                ></textarea>
            </div>
            <button type="submit" className="bg-brand hover:bg-opacity-90 text-white font-black uppercase tracking-widest text-xs py-4 px-10 rounded-2xl transition-all shadow-xl active:scale-95">
                Publish Incident & Update Status
            </button>
        </form>

        <div className="space-y-8">
            <h3 className="text-sm font-black uppercase tracking-widest text-zinc-500">Incident Timeline</h3>
            {state.incidents.length > 0 ? (
                <div className="space-y-4">
                    {[...state.incidents].reverse().map(incident => (
                        <div key={incident.id} className={`flex items-center justify-between p-6 bg-dark-950 border rounded-2xl group transition-all ${incident.status === 'active' ? 'border-orange-500/30' : 'border-dark-800'}`}>
                            <div className="flex items-center gap-6">
                                <div className={`w-12 h-12 bg-dark-900 rounded-xl flex items-center justify-center font-black border border-dark-800 ${incident.status === 'active' ? 'text-orange-500' : 'text-zinc-500'}`}>
                                    {incident.status === 'active' ? '!' : '✓'}
                                </div>
                                <div>
                                    <div className="flex items-center gap-3">
                                        <p className="font-bold text-zinc-100">{incident.title}</p>
                                        <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded ${incident.status === 'active' ? 'bg-orange-500/20 text-orange-400' : 'bg-emerald-500/20 text-emerald-400'}`}>
                                            {incident.status}
                                        </span>
                                        <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded border ${
                                            incident.impactStatus === 'down' ? 'border-rose-500/30 text-rose-400' : 
                                            incident.impactStatus === 'partial' ? 'border-orange-500/30 text-orange-400' : 
                                            'border-emerald-500/30 text-emerald-400'
                                        }`}>
                                            {incident.impactStatus}
                                        </span>
                                    </div>
                                    <p className="text-[10px] text-zinc-500 font-black uppercase tracking-widest mt-1">
                                        {incident.date} <span className="text-brand font-black ml-3">{incident.time}</span>
                                        <span className="mx-3 text-zinc-700">|</span>
                                        Affected: <span className="text-zinc-300">{state.publicSystems.find(s => s.id === incident.systemId)?.name}</span>
                                    </p>
                                </div>
                            </div>
                            <div className="flex items-center gap-3">
                                {incident.status === 'active' && (
                                    <button
                                        onClick={() => handleResolveIncident(incident.id)}
                                        className="text-emerald-500 hover:text-emerald-400 text-[10px] font-black uppercase tracking-widest bg-emerald-500/5 hover:bg-emerald-500/10 px-4 py-2 rounded-xl transition-all border border-emerald-500/20"
                                    >
                                        Resolve
                                    </button>
                                )}
                                <button
                                    onClick={() => handleDeleteIncident(incident.id)}
                                    className="text-rose-500 hover:text-rose-400 text-[10px] font-black uppercase tracking-widest bg-rose-500/5 hover:bg-rose-500/10 px-4 py-2 rounded-xl transition-all"
                                >
                                    Delete
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            ) : (
                <div className="p-16 border border-dashed border-dark-800 rounded-3xl text-center">
                    <p className="text-zinc-600 font-bold italic">No incident records in database.</p>
                </div>
            )}
        </div>
      </section>
    </div>
  );
};

