import React, { useState, useEffect, useRef } from 'react';
import { HashRouter, Routes, Route, Link, useLocation, Navigate } from 'react-router-dom';
import PublicStatus from './pages/PublicStatus';
import Dashboard from './pages/Dashboard';
import AllSites from './pages/AllSites';
import SiteProfile from './pages/SiteProfile';
import PublicManagement from './pages/PublicManagement';
import Settings from './pages/Settings';
import Login from './pages/Login';
import { getStore, saveStore, notifyDiscord } from './store';
import { AppState, MonitoredSite, AppSettings, PublicSystem, Incident } from './types';
import { DashboardIcon, SettingsIcon, Globe, Shield, Activity } from './components/Icons';

const AUTH_KEY = 'madex_auth_session';

// Protected Route Component
const ProtectedRoute = ({ children, isAuthenticated }: { children: React.ReactNode, isAuthenticated: boolean }) => {
  if (!isAuthenticated) return <Navigate to="/login" replace />;
  return <>{children}</>;
};

