const App: React.FC = () => {
  const [state, setState] = useState<AppState>(getStore());
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem(AUTH_KEY) === 'true';
  });
  const lastUpdateRef = useRef<number>(Date.now());

  useEffect(() => {
    saveStore(state);
  }, [state]);

  // Handle Auth Persistence Changes
  const handleLogin = () => {
    setIsAuthenticated(true);
    localStorage.setItem(AUTH_KEY, 'true');
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem(AUTH_KEY);
  };

  // Simulated live monitoring background task
  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      const isFiveMinPassed = now - lastUpdateRef.current >= 300000; // 5 minutes in ms

      setState(prev => {
        const nextSites = prev.monitoredSites.map(site => {
            const jitter = Math.floor(Math.random() * 20) - 10;
            const currentRT = site.responseTime[site.responseTime.length - 1];
            const newRT = Math.max(30, currentRT + jitter);

            let newStatus = site.status;
            // Smaller random chance to toggle status for simulation
            if (Math.random() < 0.002) { 
                const oldStatus = site.status;
                newStatus = site.status === 'online' ? 'offline' : 'online';

                if (prev.settings.discordWebhook && oldStatus !== newStatus) {
                    const msg = `**${site.companyName}** monitor is now **${newStatus.toUpperCase()}**.\nURL: ${site.url}`;
                    notifyDiscord(prev.settings.discordWebhook, msg);
                }
            }

            let nextHistory = [...site.history];
            let nextResponseTimes = [...site.responseTime];

            // If 5 minutes have passed, we push a new status point to the high-res history
            if (isFiveMinPassed) {
              nextHistory = [...site.history.slice(1), newStatus];
              nextResponseTimes = [...site.responseTime.slice(1), newRT];
            } else {
              // Just update the latest point for "live" feel
              nextResponseTimes[nextResponseTimes.length - 1] = newRT;
            }

            return {
                ...site,
                responseTime: nextResponseTimes,
                history: nextHistory,
                status: newStatus
            };
        });

        if (isFiveMinPassed) {
          lastUpdateRef.current = now;
        }

        return { ...prev, monitoredSites: nextSites };
      });
    }, 10000); // Check every 10 seconds for UI smoothness

    return () => clearInterval(interval);
  }, []);

  const handleUpdateSites = (sites: MonitoredSite[]) => setState(prev => ({ ...prev, monitoredSites: sites }));
  const handleUpdateSettings = (settings: AppSettings) => setState(prev => ({ ...prev, settings }));
  const handleUpdatePublic = (publicSystems: PublicSystem[]) => setState(prev => ({ ...prev, publicSystems: publicSystems }));
  const handleUpdateIncidents = (incidents: Incident[]) => setState(prev => ({ ...prev, incidents: incidents }));

  return (
    <HashRouter>
      <Routes>
        <Route path="/" element={<PublicStatus state={state} />} />
        <Route path="/login" element={<Login isAuthenticated={isAuthenticated} onLogin={handleLogin} />} />

        <Route path="/dashboard" element={
          <ProtectedRoute isAuthenticated={isAuthenticated}>
            <DashboardLayout onLogout={handleLogout}>
              <Dashboard state={state} />
            </DashboardLayout>
          </ProtectedRoute>
        } />

        <Route path="/sites" element={
          <ProtectedRoute isAuthenticated={isAuthenticated}>
            <DashboardLayout onLogout={handleLogout}>
              <AllSites state={state} onUpdate={handleUpdateSites} />
            </DashboardLayout>
          </ProtectedRoute>
        } />

        <Route path="/sites/:id" element={
          <ProtectedRoute isAuthenticated={isAuthenticated}>
            <DashboardLayout onLogout={handleLogout}>
              <SiteProfile state={state} onUpdateSites={handleUpdateSites} />
            </DashboardLayout>
          </ProtectedRoute>
        } />

        <Route path="/public-management" element={
          <ProtectedRoute isAuthenticated={isAuthenticated}>
            <DashboardLayout onLogout={handleLogout}>
              <PublicManagement 
                state={state} 
                onUpdatePublic={handleUpdatePublic} 
                onUpdateIncidents={handleUpdateIncidents} 
              />
            </DashboardLayout>
          </ProtectedRoute>
        } />

        <Route path="/settings" element={
          <ProtectedRoute isAuthenticated={isAuthenticated}>
            <DashboardLayout onLogout={handleLogout}>
              <Settings
                state={state}
                onUpdateSettings={handleUpdateSettings}
              />
            </DashboardLayout>
          </ProtectedRoute>
        } />
      </Routes>
    </HashRouter>
  );
};

export default App;

