        <div className={`p-6 rounded-2xl border ${isAllOperational ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400' : 'bg-orange-500/10 border-orange-500/20 text-orange-400'} flex items-center gap-4 shadow-2xl transition-colors duration-500`}>
          {isAllOperational ? (
            <CheckCircle className="w-8 h-8" />
          ) : (
            <AlertTriangle className="w-8 h-8" />
          )}
          <span className="text-lg font-semibold">
            {isAllOperational ? 'Alle Systeme in Betrieb' : 'Einige Systeme weisen Störungen auf'}
          </span>
        </div>

        {/* Systems List */}
        <div className="grid gap-6">
          {state.publicSystems.map(system => (
            <div key={system.id} className="bg-dark-900 border border-dark-800 rounded-2xl p-6 hover:border-brand/30 transition-all shadow-lg">
              <div className="flex items-center justify-between mb-6">
                <div>
                  <h3 className="font-bold text-lg text-white">{system.name}</h3>
                  <p className="text-sm text-zinc-500">Historie der letzten 30 Tage</p>
                </div>
                <div className="flex items-center gap-2">
                  <span className={`w-2 h-2 rounded-full ${system.status === 'operational' ? 'bg-emerald-500' : system.status === 'partial' ? 'bg-orange-500' : 'bg-rose-500'} animate-pulse`}></span>
                  <span className={`text-sm font-medium uppercase tracking-wider ${system.status === 'operational' ? 'text-emerald-500' : system.status === 'partial' ? 'text-orange-500' : 'text-rose-500'}`}>
                    {getStatusLabel(system.status)}
                  </span>
                </div>
              </div>

              {/* Enhanced StatusBar with Incidents */}
              <StatusBar 
                history={system.history} 
                locale="de-DE" 
                incidents={state.incidents} 
                systemId={system.id} 
              />

              <div className="flex justify-between mt-3 text-[10px] text-zinc-600 uppercase font-bold tracking-widest">
                <span>Vor 30 Tagen</span>
                <span>Heute</span>
              </div>
            </div>
          ))}
        </div>

        {/* Incident History Section */}
        <div className="pt-12 border-t border-dark-800 space-y-12">
          {/* Active Incidents */}
          {activeIncidents.length > 0 && (
            <div>
              <h2 className="text-xl font-bold mb-8 text-orange-400 flex items-center gap-2">
                <span className="w-2 h-2 rounded-full bg-orange-500 animate-ping"></span>
                Aktive Vorfälle
              </h2>
              <div className="space-y-6">
                {activeIncidents.slice().reverse().map(incident => (
                  <IncidentItem 
                    key={incident.id} 
                    incident={incident} 
                    active 
                    systemName={state.publicSystems.find(s => s.id === incident.systemId)?.name} 
                  />
                ))}
              </div>
            </div>
          )}

          {/* Past Incidents - Only shown if resolved incidents exist, OR if no active incidents exist to show empty state */}
          {(resolvedIncidents.length > 0 || activeIncidents.length === 0) && (
            <div>
              <h2 className="text-xl font-bold mb-8 text-white">Vorfallshistorie</h2>
              <div className="space-y-6">
                {resolvedIncidents.length > 0 ? (
                    resolvedIncidents.slice().reverse().map(incident => (
                      <IncidentItem 
                        key={incident.id} 
                        incident={incident} 
                        systemName={state.publicSystems.find(s => s.id === incident.systemId)?.name} 
                      />
                    ))
                ) : (
                   <p className="text-zinc-500 italic text-sm">Keine gemeldeten Vorfälle in letzter Zeit.</p>
                )}
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <footer className="pt-16 pb-8 text-center border-t border-dark-800">
            <p className="text-sm text-zinc-600">
                &copy; {new Date().getFullYear()} Madex IT. Alle Rechte vorbehalten.
            </p>
        </footer>
      </div>
    </div>
  );
};

const IncidentItem = ({ incident, active = false, systemName }: { incident: any, active?: boolean, systemName?: string }) => {
  const getImpactLabel = (status: string) => {
    switch (status) {
      case 'down': return 'Systemausfall';
      case 'partial': return 'Teilweiser Ausfall';
      case 'operational': return 'Information';
      default: return '';
    }
  };

  return (
    <div className="flex gap-4 group">
      <div className="w-px bg-dark-800 relative group-last:bg-transparent">
          <div className={`absolute top-0 left-1/2 -translate-x-1/2 w-3 h-3 rounded-full shadow-lg ${active ? 'bg-orange-500 shadow-orange-500/50' : 'bg-brand shadow-brand/50'}`}></div>
      </div>
      <div className="pb-8 flex-1">
          <div className="flex items-center gap-3">
              <p className="text-zinc-500 text-xs font-mono">
                  {new Date(incident.date).toLocaleDateString('de-DE')}
              </p>
              {incident.time && (
                  <span className="bg-dark-800 text-zinc-400 px-2 py-0.5 rounded text-[10px] font-bold">
                      {incident.time}
                  </span>
              )}
              {systemName && (
                <span className="text-brand text-[10px] font-black uppercase tracking-widest bg-brand/5 px-2 py-0.5 rounded border border-brand/20">
                  {systemName}
                </span>
              )}
              {active && (
                <span className="text-orange-500 text-[10px] font-black uppercase tracking-widest animate-pulse flex items-center gap-1.5">
                  <span className="w-1 h-1 rounded-full bg-orange-500"></span>
                  Laufend - {getImpactLabel(incident.impactStatus)}
                </span>
              )}
          </div>
          <h4 className={`text-lg font-semibold mt-1 ${active ? 'text-zinc-100' : 'text-zinc-400'}`}>{incident.title}</h4>
          <p className={`mt-2 leading-relaxed text-sm ${active ? 'text-zinc-300' : 'text-zinc-500 italic'}`}>
            {incident.description}
            {!active && <span className="block mt-2 font-bold text-emerald-500 text-[10px] uppercase tracking-widest">Problem behoben</span>}
          </p>
      </div>
    </div>
  );
};

export default PublicStatus;

export type StatusType = 'operational' | 'partial' | 'down';

export interface Incident {
  id: string;
  date: string;
  time?: string;
  title: string;
  description: string;
  systemId: string; // Linked to PublicSystem id
  status: 'active' | 'resolved'; // Incident state
  impactStatus: StatusType; // The status this incident imposes on the system
  resolvedDate?: string;
  resolvedTime?: string;
}

export interface PublicSystem {
  id: string;
  name: string;
  status: StatusType;
  history: StatusType[]; // Last 30 days
}

export interface MonitoredSite {
  id: string;
  companyName: string;
  url: string;
  status: 'online' | 'offline' | 'warning';
  interval: number; // minutes
  timeout: number; // seconds
  method: 'GET' | 'POST' | 'HEAD';
  statusRange: string;
  keyword?: string;
  lastChecked?: string;
  responseTime: number[]; // last 24 points
  history: ('online' | 'offline' | 'warning')[]; // 30 points
}

export interface AppSettings {
  discordWebhook: string;
}

export interface AppState {
  publicSystems: PublicSystem[];
  monitoredSites: MonitoredSite[];
  incidents: Incident[];
  settings: AppSettings;
}

import React, { useState } from 'react';
import { AppState, PublicSystem, Incident, StatusType } from '../types';

interface Props {
  state: AppState;
  onUpdatePublic: (p: PublicSystem[]) => void;
  onUpdateIncidents: (i: Incident[]) => void;
}

const PublicManagement: React.FC<Props> = ({ state, onUpdatePublic, onUpdateIncidents }) => {
  const [newIncident, setNewIncident] = useState({ 
    title: '', 
    description: '', 
    date: new Date().toISOString().split('T')[0],
    time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
    systemId: state.publicSystems[0]?.id || '',
    impactStatus: 'down' as StatusType
  });

  const togglePublicStatus = (id: string) => {
      const nextStatus = (status: string) => {
          if (status === 'operational') return 'partial';
          if (status === 'partial') return 'down';
          return 'operational';
      };

      const updated = state.publicSystems.map(s => {
          if (s.id === id) {
              const newStat = nextStatus(s.status) as any;
              const newHistory = [...s.history];
              if (newHistory.length > 0) {
                  newHistory[newHistory.length - 1] = newStat;
              }
              return { ...s, status: newStat, history: newHistory };
          }
          return s;
      });
      onUpdatePublic(updated);
  };

  const updateSystemStatus = (systemId: string, status: StatusType) => {
    const updated = state.publicSystems.map(s => {
      if (s.id === systemId) {
        const newHistory = [...s.history];
        if (newHistory.length > 0) {
          newHistory[newHistory.length - 1] = status;
        }
        return { ...s, status, history: newHistory };
      }
      return s;
    });
    onUpdatePublic(updated);
  };

  const handleAddIncident = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newIncident.title || !newIncident.description || !newIncident.systemId) return;

    const incident: Incident = {
        id: Math.random().toString(36).substr(2, 9),
        ...newIncident,
        status: 'active'
    };

    onUpdateIncidents([...state.incidents, incident]);
    updateSystemStatus(newIncident.systemId, newIncident.impactStatus);

    setNewIncident({ 
        title: '', 
        description: '', 
        date: new Date().toISOString().split('T')[0],
        time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        systemId: state.publicSystems[0]?.id || '',
        impactStatus: 'down'
    });
  };

  const handleResolveIncident = (id: string) => {
    const incidentToResolve = state.incidents.find(inc => inc.id === id);
    if (!incidentToResolve) return;

    const now = new Date();
    const resolvedDate = now.toISOString().split('T')[0];
    const resolvedTime = now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

    const updatedIncidents = state.incidents.map(inc => 
      inc.id === id ? { 
        ...inc, 
        status: 'resolved' as const,
        resolvedDate,
        resolvedTime
      } : inc
    );

    onUpdateIncidents(updatedIncidents);

    const systemId = incidentToResolve.systemId;
    const otherActiveIncidents = updatedIncidents.filter(inc => inc.systemId === systemId && inc.status === 'active');

    if (otherActiveIncidents.length === 0) {
      updateSystemStatus(systemId, 'operational');
    } else {
      const priority: Record<StatusType, number> = { 'down': 3, 'partial': 2, 'operational': 1 };
      const worstStatus = otherActiveIncidents.reduce((prev, curr) => {
        return (priority[curr.impactStatus] > priority[prev]) ? curr.impactStatus : prev;
      }, 'operational' as StatusType);

      updateSystemStatus(systemId, worstStatus);
    }
  };

  const handleReopenIncident = (id: string) => {
    const incidentToReopen = state.incidents.find(inc => inc.id === id);
    if (!incidentToReopen) return;

    const updatedIncidents = state.incidents.map(inc => 
      inc.id === id ? { 
        ...inc, 
        status: 'active' as const,
        resolvedDate: undefined,
        resolvedTime: undefined
      } : inc
    );

    onUpdateIncidents(updatedIncidents);

    const systemId = incidentToReopen.systemId;
    const activeIncidents = updatedIncidents.filter(inc => inc.systemId === systemId && inc.status === 'active');

    const priority: Record<StatusType, number> = { 'down': 3, 'partial': 2, 'operational': 1 };
    const worstStatus = activeIncidents.reduce((prev, curr) => {
      return (priority[curr.impactStatus] > priority[prev]) ? curr.impactStatus : prev;
    }, 'operational' as StatusType);

    updateSystemStatus(systemId, worstStatus);
  };

  const handleDeleteIncident = (id: string) => {
    if (confirm('Are you sure you want to delete this incident permanently?')) {
        onUpdateIncidents(state.incidents.filter(i => i.id !== id));
    }
  };

  return (
    <div className="space-y-10 animate-in fade-in duration-500">
      <div>
        <h1 className="text-3xl font-black tracking-tight text-white">Public Status Management</h1>
        <p className="text-zinc-500 mt-1">Control how your services are displayed on the public status page.</p>
      </div>

      <section className="bg-dark-900 border border-dark-800 rounded-3xl p-8 shadow-xl">
        <div className="flex items-center justify-between mb-8">
            <div>
                <h2 className="text-xl font-bold mb-2">System Health Control</h2>
                <p className="text-zinc-500 text-sm">Manually override service status. Note: Active incidents may override this.</p>
            </div>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {state.publicSystems.map(system => {
                const hasActiveIncident = state.incidents.some(inc => inc.systemId === system.id && inc.status === 'active');
                return (
                    <div key={system.id} className={`p-6 bg-dark-950 border rounded-2xl flex flex-col gap-4 group transition-all ${hasActiveIncident ? 'border-brand/40 shadow-[0_0_20px_rgba(2,141,134,0.1)]' : 'border-dark-800'}`}>
                        <div className="flex items-center justify-between">
                            <div className="flex flex-col">
                                <p className="font-bold text-base text-zinc-100">{system.name}</p>
                                {hasActiveIncident && (
                                    <span className="text-[9px] font-black text-brand uppercase tracking-tighter">Active Incident Linked</span>
                                )}
                            </div>
                            <div className={`w-3 h-3 rounded-full ${system.status === 'operational' ? 'bg-emerald-500' : system.status === 'partial' ? 'bg-orange-500' : 'bg-rose-500'} animate-pulse`}></div>
                        </div>
                        <div className="flex items-center justify-between">
                            <p className={`text-[10px] font-black uppercase tracking-widest ${system.status === 'operational' ? 'text-emerald-500' : system.status === 'partial' ? 'text-orange-500' : 'text-rose-500'}`}>
                                {system.status}
                            </p>
                            <button
                                onClick={() => togglePublicStatus(system.id)}
                                className="text-xs font-black uppercase tracking-tighter text-zinc-400 hover:text-white bg-dark-800 hover:bg-dark-700 px-4 py-2 rounded-xl transition-all"
                            >
                                Cycle Status
                            </button>
                        </div>
                    </div>
                );
            })}
        </div>
      </section>

      <section className="bg-dark-900 border border-dark-800 rounded-3xl p-8 shadow-xl">
        <h2 className="text-xl font-bold mb-2">Incident Log Manager</h2>
        <p className="text-zinc-500 text-sm mb-10">Add official service disruption records. Setting a status will update the public board.</p>

        <form onSubmit={handleAddIncident} className="space-y-6 mb-12 bg-dark-950 p-8 rounded-3xl border border-dark-800 shadow-inner">
            <h3 className="text-sm font-black uppercase tracking-widest text-brand mb-6 flex items-center gap-2">
                <span className="w-2 h-2 rounded-full bg-brand"></span>
                Record New Incident
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="space-y-1">
                    <label className="text-[10px] text-zinc-500 font-black uppercase tracking-widest ml-1">Event Title</label>
                    <input
                        required
                        type="text"
                        value={newIncident.title}
                        onChange={e => setNewIncident({...newIncident, title: e.target.value})}
                        className="w-full bg-dark-900 border border-dark-800 rounded-2xl px-5 py-3 outline-none focus:ring-1 focus:ring-brand font-bold text-sm text-white"
                        placeholder="e.g. Major Server Outage"
                    />
                </div>
                <div className="space-y-1">
                    <label className="text-[10px] text-zinc-500 font-black uppercase tracking-widest ml-1">Affected System</label>
                    <select
                        required
                        value={newIncident.systemId}
                        onChange={e => setNewIncident({...newIncident, systemId: e.target.value})}
                        className="w-full bg-dark-900 border border-dark-800 rounded-2xl px-5 py-3 outline-none focus:ring-1 focus:ring-brand font-bold text-sm text-white appearance-none"
                    >
                        {state.publicSystems.map(s => (
                            <option key={s.id} value={s.id}>{s.name}</option>
                        ))}
                    </select>
                </div>
                <div className="space-y-1">
                    <label className="text-[10px] text-zinc-500 font-black uppercase tracking-widest ml-1">Incident Severity (Status)</label>
                    <select
                        required
                        value={newIncident.impactStatus}
                        onChange={e => setNewIncident({...newIncident, impactStatus: e.target.value as StatusType})}
                        className={`w-full bg-dark-900 border border-dark-800 rounded-2xl px-5 py-3 outline-none focus:ring-1 focus:ring-brand font-bold text-sm appearance-none ${
                            newIncident.impactStatus === 'down' ? 'text-rose-500' : newIncident.impactStatus === 'partial' ? 'text-orange-500' : 'text-emerald-500'
                        }`}
                    >
                        <option value="operational">Operational (Info Only)</option>
                        <option value="partial">Partial Issues (Warning)</option>
                        <option value="down">System Down (Critical)</option>
                    </select>
                </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-1">
                    <label className="text-[10px] text-zinc-500 font-black uppercase tracking-widest ml-1">Occurrence Date</label>
                    <input
                        required
                        type="date"
                        value={newIncident.date}
                        onChange={e => setNewIncident({...newIncident, date: e.target.value})}
                        className="w-full bg-dark-900 border border-dark-800 rounded-2xl px-5 py-3 outline-none focus:ring-1 focus:ring-brand font-bold text-sm text-white"
                    />
                </div>
                <div className="space-y-1">
                    <label className="text-[10px] text-zinc-500 font-black uppercase tracking-widest ml-1">Arrival Time</label>
                    <input
                        required
                        type="time"
                        value={newIncident.time}
                        onChange={e => setNewIncident({...newIncident, time: e.target.value})}
                        className="w-full bg-dark-900 border border-dark-800 rounded-2xl px-5 py-3 outline-none focus:ring-1 focus:ring-brand font-bold text-sm text-white"
                    />
                </div>
            </div>
            <div className="space-y-1">
                <label className="text-[10px] text-zinc-500 font-black uppercase tracking-widest ml-1">Description & Mitigation</label>
                <textarea
                    required
                    value={newIncident.description}
                    onChange={e => setNewIncident({...newIncident, description: e.target.value})}
                    className="w-full bg-dark-900 border border-dark-800 rounded-2xl px-5 py-3 outline-none focus:ring-1 focus:ring-brand min-h-[120px] text-sm font-medium text-white"
                    placeholder="Provide details about the issue and any steps taken to resolve it..."
                ></textarea>
            </div>
            <button type="submit" className="bg-brand hover:bg-opacity-90 text-white font-black uppercase tracking-widest text-xs py-4 px-10 rounded-2xl transition-all shadow-xl active:scale-95">
                Publish Incident & Update Status
            </button>
        </form>

        <div className="space-y-8">
            <h3 className="text-sm font-black uppercase tracking-widest text-zinc-500">Incident Timeline</h3>
            {state.incidents.length > 0 ? (
                <div className="space-y-4">
                    {[...state.incidents].reverse().map(incident => (
                        <div key={incident.id} className={`flex items-center justify-between p-6 bg-dark-950 border rounded-2xl group transition-all ${incident.status === 'active' ? 'border-orange-500/30' : 'border-dark-800'}`}>
                            <div className="flex items-center gap-6">
                                <div className={`w-12 h-12 bg-dark-900 rounded-xl flex items-center justify-center font-black border border-dark-800 ${incident.status === 'active' ? 'text-orange-500 shadow-[0_0_15px_rgba(249,115,22,0.15)]' : 'text-zinc-500'}`}>
                                    {incident.status === 'active' ? '!' : '✓'}
                                </div>
                                <div>
                                    <div className="flex items-center gap-3">
                                        <p className="font-bold text-zinc-100">{incident.title}</p>
                                        <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded ${incident.status === 'active' ? 'bg-orange-500/20 text-orange-400' : 'bg-emerald-500/20 text-emerald-400'}`}>
                                            {incident.status}
                                        </span>
                                        <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded border ${
                                            incident.impactStatus === 'down' ? 'border-rose-500/30 text-rose-400' : 
                                            incident.impactStatus === 'partial' ? 'border-orange-500/30 text-orange-400' : 
                                            'border-emerald-500/30 text-emerald-400'
                                        }`}>
                                            {incident.impactStatus}
                                        </span>
                                    </div>
                                    <div className="flex flex-col mt-1">
                                      <p className="text-[10px] text-zinc-500 font-black uppercase tracking-widest">
                                          {incident.date} <span className="text-brand font-black ml-3">{incident.time}</span>
                                          <span className="mx-3 text-zinc-700">|</span>
                                          Affected: <span className="text-zinc-300">{state.publicSystems.find(s => s.id === incident.systemId)?.name}</span>
                                      </p>
                                      {incident.status === 'resolved' && incident.resolvedDate && (
                                        <p className="text-[10px] text-emerald-500 font-black uppercase tracking-widest mt-0.5">
                                          Behoben am: {incident.resolvedDate} um {incident.resolvedTime}
                                        </p>
                                      )}
                                    </div>
                                </div>
                            </div>
                            <div className="flex items-center gap-3">
                                {incident.status === 'active' ? (
                                    <button
                                        onClick={() => handleResolveIncident(incident.id)}
                                        className="text-emerald-500 hover:text-emerald-400 text-[10px] font-black uppercase tracking-widest bg-emerald-500/5 hover:bg-emerald-500/10 px-4 py-2 rounded-xl transition-all border border-emerald-500/20"
                                    >
                                        Resolve
                                    </button>
                                ) : (
                                  <button
                                      onClick={() => handleReopenIncident(incident.id)}
                                      className="text-orange-500 hover:text-orange-400 text-[10px] font-black uppercase tracking-widest bg-orange-500/5 hover:bg-orange-500/10 px-4 py-2 rounded-xl transition-all border border-orange-500/20"
                                  >
                                      Reopen
                                  </button>
                                )}
                                <button
                                    onClick={() => handleDeleteIncident(incident.id)}
                                    className="text-rose-500 hover:text-rose-400 text-[10px] font-black uppercase tracking-widest bg-rose-500/5 hover:bg-rose-500/10 px-4 py-2 rounded-xl transition-all"
                                >
                                    Delete
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            ) : (
                <div className="p-16 border border-dashed border-dark-800 rounded-3xl text-center">
                    <p className="text-zinc-600 font-bold italic">No incident records in database.</p>
                </div>
            )}
        </div>
      </section>
    </div>
  );
};

export default PublicManagement;

import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { AppState } from '../types';
import StatusBar from '../components/StatusBar';
import { CheckCircle, AlertTriangle, Shield } from '../components/Icons';

interface Props {
  state: AppState;
}

const PublicStatus: React.FC<Props> = ({ state }) => {
  const [now, setNow] = useState(new Date());
  const isAllOperational = state.publicSystems.every(s => s.status === 'operational');

  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const formattedDateTime = now.toLocaleDateString('de-DE', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit'
  });

  const getStatusLabel = (status: string) => {
    switch (status) {
      case 'operational': return 'Betriebsbereit';
      case 'partial': return 'Teilweise Störungen';
      case 'down': return 'Ausfall';
      default: return status;
    }
  };

  const activeIncidents = state.incidents.filter(inc => inc.status === 'active');
  const resolvedIncidents = state.incidents.filter(inc => inc.status === 'resolved');

  return (
    <div className="min-h-screen bg-dark-950 px-4 py-8 md:py-16">
      <div className="max-w-4xl mx-auto space-y-12">
        {/* Header */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-brand rounded-lg flex items-center justify-center shadow-[0_0_20px_rgba(2,141,134,0.3)]">
              <Shield className="w-6 h-6 text-white" />
            </div>
            <div>
              <h1 className="text-2xl font-bold tracking-tight text-white">Madex Status</h1>
              <p className="text-[10px] text-zinc-500 font-mono uppercase tracking-widest mt-0.5">
                {formattedDateTime}
              </p>
            </div>
          </div>
          <Link
            to="/login"
            className="text-sm font-medium text-zinc-400 hover:text-brand transition-colors"
          >
            Admin Dashboard →
          </Link>
        </div>

        {/* Global Status Banner */}
        <div className={`p-6 rounded-2xl border ${isAllOperational ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400' : 'bg-orange-500/10 border-orange-500/20 text-orange-400'} flex items-center gap-4 shadow-2xl transition-colors duration-500`}>
          {isAllOperational ? (
            <CheckCircle className="w-8 h-8" />
          ) : (
            <AlertTriangle className="w-8 h-8" />
          )}
          <span className="text-lg font-semibold">
            {isAllOperational ? 'Alle Systeme in Betrieb' : 'Einige Systeme weisen Störungen auf'}
          </span>
        </div>

        {/* Systems List */}
        <div className="grid gap-6">
          {state.publicSystems.map(system => (
            <div key={system.id} className="bg-dark-900 border border-dark-800 rounded-2xl p-6 hover:border-brand/30 transition-all shadow-lg">
              <div className="flex items-center justify-between mb-6">
                <div>
                  <h3 className="font-bold text-lg text-white">{system.name}</h3>
                  <p className="text-sm text-zinc-500">Historie der letzten 30 Tage</p>
                </div>
                <div className="flex items-center gap-2">
                  <span className={`w-2 h-2 rounded-full ${system.status === 'operational' ? 'bg-emerald-500' : system.status === 'partial' ? 'bg-orange-500' : 'bg-rose-500'} animate-pulse`}></span>
                  <span className={`text-sm font-medium uppercase tracking-wider ${system.status === 'operational' ? 'text-emerald-500' : system.status === 'partial' ? 'text-orange-500' : 'text-rose-500'}`}>
                    {getStatusLabel(system.status)}
                  </span>
                </div>
              </div>

              {/* Enhanced StatusBar with Incidents */}
              <StatusBar 
                history={system.history} 
                locale="de-DE" 
                incidents={state.incidents} 
                systemId={system.id} 
              />

              <div className="flex justify-between mt-3 text-[10px] text-zinc-600 uppercase font-bold tracking-widest">
                <span>Vor 30 Tagen</span>
                <span>Heute</span>
              </div>
            </div>
          ))}
        </div>

        {/* Incident History Section */}
        <div className="pt-12 border-t border-dark-800 space-y-12">
          {/* Active Incidents */}
          {activeIncidents.length > 0 && (
            <div>
              <h2 className="text-xl font-bold mb-8 text-orange-400 flex items-center gap-2">
                <span className="w-2 h-2 rounded-full bg-orange-500 animate-ping"></span>
                Aktive Vorfälle
              </h2>
              <div className="space-y-6">
                {activeIncidents.slice().reverse().map(incident => (
                  <IncidentItem 
                    key={incident.id} 
                    incident={incident} 
                    active 
                    systemName={state.publicSystems.find(s => s.id === incident.systemId)?.name} 
                  />
                ))}
              </div>
            </div>
          )}

          {/* Past Incidents - Only shown if resolved incidents exist, OR if no active incidents exist to show empty state */}
          {(resolvedIncidents.length > 0 || activeIncidents.length === 0) && (
            <div>
              <h2 className="text-xl font-bold mb-8 text-white">Vorfallshistorie</h2>
              <div className="space-y-6">
                {resolvedIncidents.length > 0 ? (
                    resolvedIncidents.slice().reverse().map(incident => (
                      <IncidentItem 
                        key={incident.id} 
                        incident={incident} 
                        systemName={state.publicSystems.find(s => s.id === incident.systemId)?.name} 
                      />
                    ))
                ) : (
                   <p className="text-zinc-500 italic text-sm">Keine gemeldeten Vorfälle in letzter Zeit.</p>
                )}
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <footer className="pt-16 pb-8 text-center border-t border-dark-800">
            <p className="text-sm text-zinc-600">
                &copy; {new Date().getFullYear()} Madex IT. Alle Rechte vorbehalten.
            </p>
        </footer>
      </div>
    </div>
  );
};

const IncidentItem = ({ incident, active = false, systemName }: { incident: any, active?: boolean, systemName?: string }) => {
  const getImpactLabel = (status: string) => {
    switch (status) {
      case 'down': return 'Systemausfall';
      case 'partial': return 'Teilweiser Ausfall';
      case 'operational': return 'Information';
      default: return '';
    }
  };

  return (
    <div className="flex gap-4 group">
      <div className="w-px bg-dark-800 relative group-last:bg-transparent">
          <div className={`absolute top-0 left-1/2 -translate-x-1/2 w-3 h-3 rounded-full shadow-lg ${active ? 'bg-orange-500 shadow-orange-500/50' : 'bg-brand shadow-brand/50'}`}></div>
      </div>
      <div className="pb-8 flex-1">
          <div className="flex items-center gap-3">
              <p className="text-zinc-500 text-xs font-mono">
                  {new Date(incident.date).toLocaleDateString('de-DE')}
              </p>
              {incident.time && (
                  <span className="bg-dark-800 text-zinc-400 px-2 py-0.5 rounded text-[10px] font-bold">
                      {incident.time}
                  </span>
              )}
              {systemName && (
                <span className="text-brand text-[10px] font-black uppercase tracking-widest bg-brand/5 px-2 py-0.5 rounded border border-brand/20">
                  {systemName}
                </span>
              )}
              {active && (
                <span className="text-orange-500 text-[10px] font-black uppercase tracking-widest animate-pulse flex items-center gap-1.5">
                  <span className="w-1 h-1 rounded-full bg-orange-500"></span>
                  Laufend - {getImpactLabel(incident.impactStatus)}
                </span>
              )}
          </div>
          <h4 className={`text-lg font-semibold mt-1 ${active ? 'text-zinc-100' : 'text-zinc-400'}`}>{incident.title}</h4>
          <div className={`mt-2 leading-relaxed text-sm ${active ? 'text-zinc-300' : 'text-zinc-500 italic'}`}>
            {incident.description}
            {!active && (
              <div className="mt-2 flex flex-col gap-1">
                <span className="font-bold text-emerald-500 text-[10px] uppercase tracking-widest flex items-center gap-1.5">
                  <CheckCircle className="w-3 h-3" />
                  Problem behoben
                </span>
                {incident.resolvedDate && (
                  <span className="text-[10px] text-zinc-600 font-bold uppercase tracking-widest">
                    Behoben am {new Date(incident.resolvedDate).toLocaleDateString('de-DE')} um {incident.resolvedTime}
                  </span>
                )}
              </div>
            )}
          </div>
      </div>
    </div>
  );
};

export default PublicStatus;

import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { AppState, MonitoredSite } from '../types';
import StatusBar from '../components/StatusBar';
import { Globe, AlertTriangle, CheckCircle, XCircle } from '../components/Icons';

interface Props {
  state: AppState;
  onUpdate: (sites: MonitoredSite[]) => void;
}

type FilterStatus = 'all' | 'online' | 'warning' | 'offline';

const AllSites: React.FC<Props> = ({ state, onUpdate }) => {
  const navigate = useNavigate();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [editingSite, setEditingSite] = useState<MonitoredSite | null>(null);
  const [siteToDelete, setSiteToDelete] = useState<MonitoredSite | null>(null);

  // Filtering states
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<FilterStatus>('all');

  const [formData, setFormData] = useState<Partial<MonitoredSite>>({
    companyName: '',
    url: '',
    interval: 5,
    timeout: 30,
    method: 'GET',
    statusRange: '200-399',
    keyword: ''
  });

  const filteredSites = useMemo(() => {
    return state.monitoredSites.filter(site => {
      const matchesSearch = site.companyName.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           site.url.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesStatus = statusFilter === 'all' || site.status === statusFilter;
      return matchesSearch && matchesStatus;
    });
  }, [state.monitoredSites, searchQuery, statusFilter]);

  const handleOpenAdd = () => {
    setEditingSite(null);
    setFormData({
      companyName: '',
      url: '',
      interval: 5,
      timeout: 30,
      method: 'GET',
      statusRange: '200-399',
      keyword: ''
    });
    setIsModalOpen(true);
  };

  const handleOpenEdit = (site: MonitoredSite) => {
    setEditingSite(site);
    setFormData(site);
    setIsModalOpen(true);
  };

  const requestDelete = (site: MonitoredSite) => {
    setSiteToDelete(site);
    setIsDeleteModalOpen(true);
  };

  const confirmDelete = () => {
    if (siteToDelete) {
      onUpdate(state.monitoredSites.filter(s => s.id !== siteToDelete.id));
      setIsDeleteModalOpen(false);
      setSiteToDelete(null);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingSite) {
      const updated = state.monitoredSites.map(s => s.id === editingSite.id ? { ...s, ...formData } as MonitoredSite : s);
      onUpdate(updated);
    } else {
      const newSite: MonitoredSite = {
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        status: 'online',
        responseTime: Array(24).fill(150),
        history: Array(30).fill('online'),
      } as MonitoredSite;
      onUpdate([...state.monitoredSites, newSite]);
    }
    setIsModalOpen(false);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-extrabold tracking-tight">Monitored Endpoints</h1>
          <p className="text-zinc-500 mt-1">Manage and configure your real-time 5-minute interval monitoring service.</p>
        </div>
        <button
          onClick={handleOpenAdd}
          className="bg-brand hover:bg-opacity-90 text-white px-8 py-4 rounded-2xl font-bold transition-all shadow-[0_10px_30px_rgba(2,141,134,0.3)] active:scale-95 shrink-0"
        >
          + Add New Monitor
        </button>
      </div>

      {/* Filters Bar */}
      <div className="flex flex-col md:flex-row gap-4 bg-dark-900/50 border border-dark-800 p-4 rounded-3xl shadow-lg">
         <div className="flex-1 relative">
            <input 
               type="text"
               placeholder="Search by name or URL..."
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
               className="w-full bg-dark-950 border border-dark-800 rounded-2xl py-3 px-5 pl-12 outline-none focus:ring-1 focus:ring-brand transition-all text-sm"
            />
            <Globe className="w-5 h-5 text-zinc-600 absolute left-4 top-1/2 -translate-y-1/2" />
         </div>
         <div className="flex gap-2">
            {(['all', 'online', 'warning', 'offline'] as FilterStatus[]).map((status) => (
              <button
                key={status}
                onClick={() => setStatusFilter(status)}
                className={`px-4 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest border transition-all ${
                  statusFilter === status 
                    ? 'bg-brand/10 border-brand text-brand' 
                    : 'bg-dark-950 border-dark-800 text-zinc-500 hover:border-dark-700'
                }`}
              >
                {status}
              </button>
            ))}
         </div>
      </div>

      <div className="grid gap-6">
        {filteredSites.map(site => (
          <div key={site.id} className="bg-dark-900 border border-dark-800 rounded-3xl p-8 hover:border-brand/40 transition-all flex flex-col lg:flex-row lg:items-center gap-10 shadow-xl group">
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-4 mb-2">
                <button 
                  onClick={() => navigate(`/sites/${site.id}`)}
                  className="w-14 h-14 bg-dark-950 border border-dark-800 rounded-2xl flex items-center justify-center font-black text-xl text-brand hover:border-brand transition-colors shadow-inner"
                >
                  {site.companyName.charAt(0).toUpperCase()}
                </button>
                <div>
                  <h3 className="font-extrabold text-2xl group-hover:text-brand transition-colors tracking-tight cursor-pointer" onClick={() => navigate(`/sites/${site.id}`)}>{site.companyName}</h3>
                  <div className="flex items-center gap-3 mt-1.5">
                    <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest border ${
                      site.status === 'online' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' : 
                      site.status === 'warning' ? 'bg-orange-500/10 text-orange-400 border-orange-500/20' : 
                      'bg-rose-500/10 text-rose-400 border-rose-500/20'
                    }`}>
                        {site.status}
                    </span>
                    <p className="text-zinc-600 text-sm font-mono truncate max-w-xs">{site.url}</p>
                  </div>
                </div>
              </div>

              <div className="mt-8">
                 <div className="flex justify-between items-center mb-3">
                    <span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest flex items-center gap-2">
                      <span className="w-1.5 h-1.5 rounded-full bg-brand animate-pulse"></span>
                      Real-time Uptime (5m Intervals)
                    </span>
                    <span className="text-[10px] font-bold text-zinc-600">LAST 2.5 HOURS</span>
                 </div>
                 <StatusBar history={site.history} isHighRes={true} />
              </div>
            </div>

            <div className="flex flex-col lg:items-end justify-center gap-4 lg:w-72 lg:border-l lg:border-dark-800 lg:pl-10 shrink-0">
              <div className="flex justify-between w-full lg:flex-col lg:items-end gap-1">
                <span className="text-[10px] text-zinc-500 font-black uppercase tracking-widest">Polling Interval</span>
                <span className="text-sm font-bold text-zinc-200">{site.interval} minutes</span>
              </div>
              <div className="flex justify-between w-full lg:flex-col lg:items-end gap-1">
                <span className="text-[10px] text-zinc-500 font-black uppercase tracking-widest">Avg Response</span>
                <span className="text-lg font-black text-brand">{(site.responseTime.reduce((a,b)=>a+b,0)/site.responseTime.length).toFixed(0)}ms</span>
              </div>
              <div className="flex flex-wrap gap-2 mt-4 w-full justify-end">
                <button 
                  onClick={() => navigate(`/sites/${site.id}`)}
                  className="flex-1 text-[10px] font-black uppercase tracking-widest text-white bg-brand hover:bg-opacity-90 px-3 py-2.5 rounded-xl transition-all"
                >
                  Profile
                </button>
                <button 
                  onClick={() => handleOpenEdit(site)} 
                  className="flex-1 text-[10px] font-black uppercase tracking-widest text-zinc-400 hover:text-white bg-dark-800 hover:bg-dark-700 px-3 py-2.5 rounded-xl transition-all"
                >
                  Edit
                </button>
                <button 
                  onClick={() => requestDelete(site)} 
                  className="flex-1 text-[10px] font-black uppercase tracking-widest text-rose-500 hover:text-rose-400 bg-rose-500/5 hover:bg-rose-500/10 px-3 py-2.5 rounded-xl transition-all"
                >
                  Delete
                </button>
              </div>
            </div>
          </div>
        ))}

        {filteredSites.length === 0 && (
          <div className="bg-dark-900 border border-dashed border-dark-800 rounded-3xl p-24 text-center">
            <Globe className="w-16 h-16 text-zinc-800 mx-auto mb-6" />
            <h3 className="text-2xl font-bold text-zinc-500">No matching monitors</h3>
            <p className="text-zinc-600 mt-2">Try adjusting your filters or search query.</p>
            <button 
              onClick={() => {setSearchQuery(''); setStatusFilter('all');}}
              className="mt-6 text-brand font-bold hover:underline"
            >
              Reset all filters
            </button>
          </div>
        )}
      </div>

      {/* Edit/Add Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-md z-50 flex items-center justify-center p-4 animate-in fade-in duration-200">
          <div className="bg-dark-900 border border-dark-800 w-full max-w-xl rounded-[40px] p-12 shadow-2xl animate-in zoom-in-95 duration-200 overflow-hidden relative">
            <div className="absolute top-0 left-0 w-full h-2 bg-brand opacity-20"></div>
            <h2 className="text-3xl font-black mb-10 tracking-tight">{editingSite ? 'Modify Monitor' : 'New Monitor'}</h2>
            <form onSubmit={handleSubmit} className="space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Company Name</label>
                  <input
                    required
                    type="text"
                    value={formData.companyName}
                    onChange={e => setFormData({ ...formData, companyName: e.target.value })}
                    className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-brand/30 focus:border-brand outline-none transition-all font-medium text-white"
                    placeholder="Acme Corp"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Endpoint URL</label>
                  <input
                    required
                    type="url"
                    value={formData.url}
                    onChange={e => setFormData({ ...formData, url: e.target.value })}
                    className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-brand/30 focus:border-brand outline-none transition-all font-medium text-white"
                    placeholder="https://api.acme.com"
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-2">
                    <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Interval (min)</label>
                    <input
                        type="number"
                        min="1"
                        value={formData.interval}
                        onChange={e => setFormData({ ...formData, interval: Number(e.target.value) })}
                        className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-brand/30 focus:border-brand outline-none transition-all font-medium text-white"
                    />
                </div>
                <div className="space-y-2">
                    <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Timeout (sec)</label>
                    <input
                        type="number"
                        value={formData.timeout}
                        onChange={e => setFormData({ ...formData, timeout: Number(e.target.value) })}
                        className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-brand/30 focus:border-brand outline-none transition-all font-medium text-white"
                    />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-2">
                    <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Check Method</label>
                    <select
                        value={formData.method}
                        onChange={e => setFormData({ ...formData, method: e.target.value as any })}
                        className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-brand/30 focus:border-brand outline-none transition-all appearance-none font-medium text-white"
                    >
                        <option value="GET">HTTP GET</option>
                        <option value="POST">HTTP POST</option>
                        <option value="HEAD">HTTP HEAD</option>
                    </select>
                </div>
                <div className="space-y-2">
                    <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Expected Status</label>
                    <input
                        type="text"
                        value={formData.statusRange}
                        onChange={e => setFormData({ ...formData, statusRange: e.target.value })}
                        className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-brand/30 focus:border-brand outline-none transition-all font-medium text-white"
                        placeholder="200-399"
                    />
                </div>
              </div>

              <div className="flex gap-4 pt-10">
                <button
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="flex-1 px-8 py-5 rounded-[20px] border border-dark-800 text-zinc-500 font-black uppercase tracking-widest hover:bg-dark-800 hover:text-white transition-all text-xs"
                >
                  Discard
                </button>
                <button
                  type="submit"
                  className="flex-1 px-8 py-5 rounded-[20px] bg-brand text-white font-black uppercase tracking-widest hover:bg-opacity-90 transition-all shadow-xl text-xs"
                >
                  {editingSite ? 'Save Changes' : 'Create Monitor'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Delete Confirmation Modal */}
      {isDeleteModalOpen && siteToDelete && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-md z-[60] flex items-center justify-center p-4 animate-in fade-in duration-200">
          <div className="bg-dark-900 border border-dark-800 w-full max-w-md rounded-[40px] p-10 shadow-2xl animate-in zoom-in-95 duration-200 text-center">
            <div className="w-20 h-20 bg-rose-500/10 text-rose-500 rounded-3xl flex items-center justify-center mx-auto mb-6">
              <AlertTriangle className="w-10 h-10" />
            </div>
            <h2 className="text-2xl font-black mb-2 tracking-tight">Monitor fshirjes</h2>
            <p className="text-zinc-500 text-sm mb-8 leading-relaxed">
              A jeni të sigurt që dëshironi të fshini monitorimin për <span className="text-white font-bold">{siteToDelete.companyName}</span>?<br/>Ky veprim nuk mund të kthehet.
            </p>
            <div className="flex gap-4">
              <button
                onClick={() => setIsDeleteModalOpen(false)}
                className="flex-1 py-4 rounded-2xl border border-dark-800 text-zinc-500 font-black uppercase tracking-widest hover:bg-dark-800 hover:text-white transition-all text-[10px]"
              >
                Anulo
              </button>
              <button
                onClick={confirmDelete}
                className="flex-1 py-4 rounded-2xl bg-rose-500 text-white font-black uppercase tracking-widest hover:bg-rose-600 transition-all shadow-xl text-[10px]"
              >
                Po, Fshije
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AllSites;

import React, { useMemo, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { AppState, MonitoredSite } from '../types';
import StatusBar from '../components/StatusBar';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';
import { CheckCircle, AlertTriangle, XCircle, Globe, Shield } from '../components/Icons';

interface Props {
  state: AppState;
  onUpdateSites: (sites: MonitoredSite[]) => void;
}

const SiteProfile: React.FC<Props> = ({ state, onUpdateSites }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [isChecking, setIsChecking] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);

  const site = useMemo(() => {
    return state.monitoredSites.find(s => s.id === id);
  }, [state.monitoredSites, id]);

  if (!site) {
