import React, { useState, useEffect, useRef, Suspense, lazy } from 'react';
import { HashRouter, Routes, Route, Link, useLocation, Navigate } from 'react-router-dom';
import { getStore, saveStore, notifyDiscord } from './store';
import { AppState, MonitoredSite, AppSettings, PublicSystem, Incident } from './types';
import { DashboardIcon, SettingsIcon, Globe, Shield, Activity } from './components/Icons';

// Lazy loading components to reduce initial bundle size and fix chunk size warnings
const PublicStatus = lazy(() => import('./pages/PublicStatus'));
const Dashboard = lazy(() => import('./pages/Dashboard'));
const AllSites = lazy(() => import('./pages/AllSites'));
const SiteProfile = lazy(() => import('./pages/SiteProfile'));
const PublicManagement = lazy(() => import('./pages/PublicManagement'));
const Settings = lazy(() => import('./pages/Settings'));
const Login = lazy(() => import('./pages/Login'));

const AUTH_KEY = 'madex_auth_session';

const LoadingFallback = () => (
  <div className="min-h-screen bg-dark-950 flex items-center justify-center">
    <div className="w-10 h-10 border-4 border-brand border-t-transparent rounded-full animate-spin"></div>
