interface Props {
  state: AppState;
}

const PublicStatus: React.FC<Props> = ({ state }) => {
  const [now, setNow] = useState(new Date());
  const isAllOperational = state.publicSystems.every(s => s.status === 'operational');

  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const formattedDateTime = now.toLocaleDateString('de-DE', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit'
  });

  const getStatusLabel = (status: string) => {
    switch (status) {
      case 'operational': return 'Betriebsbereit';
      case 'partial': return 'Teilweise Störungen';
      case 'down': return 'Ausfall';
      default: return status;
    }
  };

