        <footer className="pt-20 pb-12 text-center border-t border-dark-800">
            <div className="flex flex-col items-center gap-6">
              <div className="flex items-center gap-4 grayscale opacity-40 hover:grayscale-0 hover:opacity-100 transition-all cursor-default group">
                <Shield className="w-6 h-6 text-brand" />
                <span className="font-black text-sm uppercase tracking-[0.4em] text-zinc-300 group-hover:text-brand transition-colors">Madex Security Systems</span>
