const IncidentItem: React.FC<{ incident: any; active?: boolean; systemName?: string }> = ({ incident, active = false, systemName }) => {
  return (
    <div className="flex gap-6 group animate-in slide-in-from-right-8 duration-500">
      <div className="w-px bg-dark-800 relative group-last:bg-transparent mt-2">
          <div className={`absolute top-0 left-1/2 -translate-x-1/2 w-3.5 h-3.5 rounded-full shadow-2xl transition-transform group-hover:scale-125 border-4 border-dark-900 ${active ? 'bg-orange-500 shadow-orange-500/40' : 'bg-zinc-700'}`}></div>
      </div>
      <div className="pb-2 flex-1 min-w-0">
          <div className="flex flex-col gap-2">
              <p className="text-zinc-500 text-[10px] font-bold font-mono uppercase tracking-tighter">
                  {new Date(incident.date).toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit', year: 'numeric' })}
                  {incident.time && ` • ${incident.time}`}
              </p>
              <div className="flex flex-wrap gap-2">
                {systemName && (
                  <span className="text-brand text-[9px] font-black uppercase tracking-widest bg-brand/10 px-2 py-0.5 rounded border border-brand/20">
                    {systemName}
                  </span>
                )}
                {active && (
                   <span className="text-orange-500 text-[9px] font-black uppercase tracking-widest animate-pulse bg-orange-500/10 px-2 py-0.5 rounded border border-orange-500/20">
                      Aktuell
                   </span>
                )}
              </div>
          </div>
          <h4 className={`text-lg font-black mt-3 tracking-tight leading-snug ${active ? 'text-zinc-100' : 'text-zinc-400 group-hover:text-zinc-300 transition-colors'}`}>{incident.title}</h4>
          <p className={`mt-2 text-sm leading-relaxed ${active ? 'text-zinc-400' : 'text-zinc-600 italic'}`}>
            {incident.description}
          </p>

          {!active && incident.resolvedDate && (
             <div className="mt-4 text-[10px] font-black text-emerald-500 uppercase tracking-widest flex items-center gap-2">
                <CheckCircle className="w-4 h-4" />
                Behoben am {new Date(incident.resolvedDate).toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit' })}
             </div>
          )}
      </div>
    </div>
  );
};

