const StatCard = ({ title, value, icon, color, isActive, onClick }: { title: string, value: number, icon: React.ReactNode, color: string, isActive: boolean, onClick: () => void }) => {
  const colorMap: any = {
    brand: isActive ? 'border-brand ring-2 ring-brand/20 bg-brand/10' : 'hover:border-brand/50 bg-brand/5',
    emerald: isActive ? 'border-emerald-500 ring-2 ring-emerald-500/20 bg-emerald-500/10' : 'hover:border-emerald-500/50 bg-emerald-500/5',
    orange: isActive ? 'border-orange-500 ring-2 ring-orange-500/20 bg-orange-500/10' : 'hover:border-orange-500/50 bg-orange-500/5',
    rose: isActive ? 'border-rose-500 ring-2 ring-rose-500/20 bg-rose-500/10' : 'hover:border-rose-500/50 bg-rose-500/5',
  };
  return (
    <button onClick={onClick} className={`text-left w-full border border-dark-800 rounded-3xl p-6 shadow-xl flex items-center justify-between group transition-all duration-300 ${colorMap[color]}`}>
      <div>
        <p className="text-[10px] text-zinc-500 font-black uppercase tracking-wider">{title}</p>
        <p className="text-4xl font-black mt-2 tracking-tighter">{value}</p>
      </div>
      <div className={`p-4 rounded-2xl transition-transform shadow-inner ${isActive ? 'bg-dark-900 scale-110' : 'bg-dark-950 group-hover:scale-110'}`}>{icon}</div>
    </button>
  );
};

