                                            {incident.status === 'active' ? 'Aktiv' : 'Gelöst'}
                                        </span>
                                        <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded border ${
                                            incident.impactStatus === 'major' ? 'border-rose-500/30 text-rose-400' : 
                                            incident.impactStatus === 'partial' ? 'border-orange-500/30 text-orange-400' : 
                                            incident.impactStatus === 'degraded' ? 'border-yellow-400/30 text-yellow-400' :
                                            incident.impactStatus === 'maintenance' ? 'border-indigo-400/30 text-indigo-400' :
                                            'border-brand/30 text-brand'
                                        }`}>
                                            {getStatusLabelDE(incident.impactStatus)}
                                        </span>
                                    </div>
                                    <div className="flex flex-col mt-1">
                                      <p className="text-[10px] text-zinc-500 font-black uppercase tracking-widest">
                                          {incident.date} <span className="text-brand font-black ml-3">{incident.time}</span>
                                          <span className="mx-3 text-zinc-700">|</span>
                                          Dienst: <span className="text-zinc-300">{state.publicSystems.find(s => s.id === incident.systemId)?.name}</span>
                                      </p>
                                    </div>
                                </div>
                            </div>
                            <div className="flex items-center gap-3">
                                {incident.status === 'active' ? (
                                    <button
                                        onClick={() => handleResolveIncident(incident.id)}
