                                    >
                                        Beheben
                                    </button>
                                ) : (
                                  <button
                                      onClick={() => handleReopenIncident(incident.id)}
                                      className="text-orange-500 hover:text-orange-400 text-[10px] font-black uppercase tracking-widest bg-orange-500/5 hover:bg-orange-500/10 px-4 py-2 rounded-xl transition-all border border-orange-500/20"
                                  >
                                      Wiedereröffnen
                                  </button>
                                )}
                                <button
                                    onClick={() => handleDeleteIncident(incident.id)}
                                    className="text-rose-500 hover:text-rose-400 text-[10px] font-black uppercase tracking-widest bg-rose-500/5 hover:bg-rose-500/10 px-4 py-2 rounded-xl transition-all"
                                >
                                    Löschen
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            ) : (
                <div className="p-16 border border-dashed border-dark-800 rounded-3xl text-center">
                    <p className="text-zinc-600 font-bold italic">Keine Vorfälle in der Datenbank.</p>
                </div>
            )}
        </div>
      </section>
    </div>
  );
};

