export type StatusType = 'operational' | 'degraded' | 'partial' | 'major' | 'maintenance';

export interface Incident {
  id: string;
  date: string;
  time?: string;
  title: string;
  description: string;
  systemId: string; // Linked to PublicSystem id
  status: 'active' | 'resolved'; // Incident state
  impactStatus: StatusType; // The status this incident imposes on the system
  resolvedDate?: string;
  resolvedTime?: string;
}

export interface PublicSystem {
  id: string;
  name: string;
  status: StatusType;
  history: StatusType[]; // Last 30 days
}

export interface MonitoredSite {
  id: string;
  companyName: string;
  url: string;
  status: 'online' | 'offline' | 'warning';
  interval: number; // minutes
  timeout: number; // seconds
  method: 'GET' | 'POST' | 'HEAD';
  statusRange: string;
  keyword?: string;
  lastChecked?: string;
  responseTime: number[]; // last 24 points
  history: ('online' | 'offline' | 'warning')[]; // 30 points
}

export interface DatabaseConfig {
  host: string;
  username: string;
  password?: string;
  databaseName: string;
  isConnected: boolean;
}

export interface AppSettings {
  discordWebhook: string;
  isTempLoginEnabled: boolean;
  dbConfig: DatabaseConfig;
}

export interface AppState {
  publicSystems: PublicSystem[];
  monitoredSites: MonitoredSite[];
  incidents: Incident[];
  settings: AppSettings;
}

