            </div>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            {state.publicSystems.map(system => {
                const hasActiveIncident = state.incidents.some(inc => inc.systemId === system.id && inc.status === 'active');
                return (
                    <div key={system.id} className={`p-6 bg-dark-950 border rounded-2xl flex flex-col gap-4 group transition-all ${hasActiveIncident ? 'border-brand/40 shadow-[0_0_20px_rgba(2,141,134,0.1)]' : 'border-dark-800'}`}>
                        <div className="flex items-center justify-between">
                            <div className="flex flex-col">
                                <p className="font-bold text-base text-zinc-100">{system.name}</p>
                                {hasActiveIncident && (
                                    <span className="text-[9px] font-black text-brand uppercase tracking-tighter">Aktiver Vorfall</span>
                                )}
                            </div>
                            <div className={`w-3 h-3 rounded-full ${
                              system.status === 'operational' ? 'bg-brand' : 
                              system.status === 'degraded' ? 'bg-yellow-400' : 
                              system.status === 'partial' ? 'bg-orange-500' : 
                              system.status === 'maintenance' ? 'bg-indigo-500' : 
                              'bg-rose-500'
                            } animate-pulse`}></div>
                        </div>
                        <div className="flex items-center justify-between">
                            <p className={`text-[10px] font-black uppercase tracking-widest ${
                              system.status === 'operational' ? 'text-brand' : 
                              system.status === 'degraded' ? 'text-yellow-400' : 
                              system.status === 'partial' ? 'text-orange-500' : 
                              system.status === 'maintenance' ? 'text-indigo-400' : 
                              'text-rose-500'
                            }`}>
                                {getStatusLabelDE(system.status)}
                            </p>
                            <button
                                onClick={() => togglePublicStatus(system.id)}
                                className="text-xs font-black uppercase tracking-tighter text-zinc-400 hover:text-white bg-dark-800 hover:bg-dark-700 px-4 py-2 rounded-xl transition-all"
                            >
                                Ändern
                            </button>
