}

const Settings: React.FC<Props> = ({ state, onUpdateSettings }) => {
  const [webhook, setWebhook] = useState(state.settings.discordWebhook);
  const [isTempEnabled, setIsTempEnabled] = useState(state.settings.isTempLoginEnabled);
  const [checkInterval, setCheckInterval] = useState(state.settings.checkInterval);
  const [identity, setIdentity] = useState<SiteIdentity>(state.settings.identity);
  const [dbConfig, setDbConfig] = useState<DatabaseConfig>(state.settings.dbConfig);

  const [isSaved, setIsSaved] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, key: keyof SiteIdentity) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setIdentity(prev => ({ ...prev, [key]: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveAll = () => {
    onUpdateSettings({ 
      ...state.settings, 
      discordWebhook: webhook,
      isTempLoginEnabled: isTempEnabled,
