import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { AppState, MonitoredSite } from '../types';
import StatusBar from '../components/StatusBar';
import { Globe, AlertTriangle, CheckCircle, XCircle, Activity } from '../components/Icons';

interface Props {
  state: AppState;
  onUpdate: (sites: MonitoredSite[]) => void;
}

type FilterStatus = 'all' | 'online' | 'warning' | 'offline';

const AllSites: React.FC<Props> = ({ state, onUpdate }) => {
  const navigate = useNavigate();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingSite, setEditingSite] = useState<MonitoredSite | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<FilterStatus>('all');

  const [formData, setFormData] = useState<Partial<MonitoredSite>>({
    companyName: '',
    url: '',
    interval: 5,
    timeout: 30,
    method: 'GET',
    statusRange: '200-399',
    authType: 'none',
    headers: [],
    body: ''
  });

  const filteredSites = useMemo(() => {
    return state.monitoredSites.filter(site => {
      const matchesSearch = site.companyName.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           site.url.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesStatus = statusFilter === 'all' || site.status === statusFilter;
      return matchesSearch && matchesStatus;
    });
  }, [state.monitoredSites, searchQuery, statusFilter]);

  const handleOpenAdd = () => {
    setEditingSite(null);
    setFormData({
      companyName: '',
      url: '',
      interval: 5,
      timeout: 30,
      method: 'GET',
      statusRange: '200-399',
      authType: 'none',
      headers: [],
      body: ''
    });
    setIsModalOpen(true);
  };

  const handleOpenEdit = (site: MonitoredSite) => {
    setEditingSite(site);
    setFormData(site);
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingSite) {
      const updated = state.monitoredSites.map(s => s.id === editingSite.id ? { ...s, ...formData } as MonitoredSite : s);
      onUpdate(updated);
    } else {
      const newSite: MonitoredSite = {
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        status: 'online',
        responseTime: Array(24).fill(150),
        history: Array(24).fill('online'),
      } as MonitoredSite;
      onUpdate([...state.monitoredSites, newSite]);
    }
    setIsModalOpen(false);
  };

  const addHeader = () => {
    const nextHeaders = [...(formData.headers || []), { key: '', value: '' }];
    setFormData({ ...formData, headers: nextHeaders });
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-brand/10 rounded-2xl flex items-center justify-center text-brand">
            <Activity className="w-8 h-8" />
          </div>
          <div>
            <h1 className="text-3xl font-black text-white tracking-tight">Monitor-Zentrum</h1>
            <p className="text-zinc-500 text-sm font-medium">Uptime Kuma Style Management.</p>
          </div>
        </div>
        <button
          onClick={handleOpenAdd}
          className="bg-brand hover:brightness-110 text-white px-8 py-4 rounded-2xl font-black uppercase tracking-widest text-xs transition-all shadow-xl active:scale-95"
        >
          + Neuer Monitor
        </button>
      </div>

      <div className="flex flex-col md:flex-row gap-4 bg-dark-900 border border-dark-800 p-4 rounded-3xl shadow-xl">
         <div className="flex-1 relative">
            <input 
               type="text"
               placeholder="Suchen..."
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
               className="w-full bg-dark-950 border border-dark-800 rounded-2xl py-3 px-5 pl-12 outline-none focus:ring-1 focus:ring-brand text-sm font-medium text-white"
            />
            <Globe className="w-5 h-5 text-zinc-600 absolute left-4 top-1/2 -translate-y-1/2" />
         </div>
      </div>

      <div className="grid grid-cols-1 gap-6">
        {filteredSites.map(site => (
          <div key={site.id} className="bg-dark-900 border border-dark-800 rounded-[32px] p-8 hover:border-brand/40 transition-all flex flex-col lg:flex-row lg:items-center gap-10 shadow-xl group">
             {/* List View Logic remains similarly structured to previous turns... */}
             <div className="flex-1 min-w-0">
               <div className="flex items-center gap-6">
                  <div className="w-16 h-16 bg-dark-950 border border-dark-800 rounded-2xl flex items-center justify-center font-black text-2xl text-brand">
                    {site.companyName.charAt(0).toUpperCase()}
                  </div>
                  <div>
                    <h3 className="font-black text-2xl text-zinc-100 group-hover:text-brand transition-colors tracking-tight">{site.companyName}</h3>
                    <p className="text-zinc-500 text-sm font-mono truncate">{site.url}</p>
                  </div>
               </div>
               <div className="mt-8">
                 <StatusBar history={site.history} isHighRes={true} />
               </div>
             </div>
             <div className="flex gap-4 shrink-0">
                <button onClick={() => handleOpenEdit(site)} className="px-6 py-3 bg-dark-950 border border-dark-800 text-zinc-400 rounded-xl text-[10px] font-black uppercase tracking-widest">Edit</button>
                <button onClick={() => onUpdate(state.monitoredSites.filter(s => s.id !== site.id))} className="px-6 py-3 bg-rose-500/10 text-rose-500 border border-rose-500/10 rounded-xl text-[10px] font-black uppercase tracking-widest">Delete</button>
             </div>
          </div>
        ))}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/95 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-dark-900 border border-dark-800 w-full max-w-4xl rounded-[40px] p-12 shadow-2xl relative max-h-[90vh] overflow-y-auto custom-scrollbar">
            <h2 className="text-3xl font-black mb-10 tracking-tight">Monitor-Spezifikationen</h2>
            <form onSubmit={handleSubmit} className="space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                 <Field label="Name" value={formData.companyName} onChange={v => setFormData({...formData, companyName: v})} />
                 <Field label="URL" value={formData.url} onChange={v => setFormData({...formData, url: v})} type="url" />
              </div>

              <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                 <Field label="Method" value={formData.method} onChange={v => setFormData({...formData, method: v as any})} select={['GET', 'POST', 'HEAD', 'PUT', 'DELETE', 'PATCH']} />
                 <Field label="Interval (m)" value={formData.interval} onChange={v => setFormData({...formData, interval: Number(v)})} type="number" />
                 <Field label="Timeout (s)" value={formData.timeout} onChange={v => setFormData({...formData, timeout: Number(v)})} type="number" />
                 <Field label="Status Range" value={formData.statusRange} onChange={v => setFormData({...formData, statusRange: v})} />
              </div>

              <div className="space-y-4">
                 <div className="flex items-center justify-between">
                   <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Custom Headers</p>
                   <button type="button" onClick={addHeader} className="text-brand text-[10px] font-black uppercase tracking-widest">+ Add Header</button>
                 </div>
                 {formData.headers?.map((h, i) => (
                   <div key={i} className="flex gap-4">
                      <input value={h.key} onChange={e => {
                        const nh = [...formData.headers!]; nh[i].key = e.target.value; setFormData({...formData, headers: nh});
                      }} className="flex-1 bg-dark-950 border border-dark-800 rounded-xl px-4 py-3 text-xs text-white" placeholder="Key" />
                      <input value={h.value} onChange={e => {
                        const nh = [...formData.headers!]; nh[i].value = e.target.value; setFormData({...formData, headers: nh});
                      }} className="flex-1 bg-dark-950 border border-dark-800 rounded-xl px-4 py-3 text-xs text-white" placeholder="Value" />
                   </div>
                 ))}
              </div>

              {['POST', 'PUT', 'PATCH'].includes(formData.method!) && (
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Request Body (JSON/Plain)</label>
                   <textarea value={formData.body} onChange={e => setFormData({...formData, body: e.target.value})} className="w-full bg-dark-950 border border-dark-800 rounded-2xl p-4 text-xs font-mono text-white h-24" />
                </div>
              )}

              <div className="flex gap-4 pt-10">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-5 rounded-2xl bg-dark-950 border border-dark-800 text-zinc-500 font-black uppercase tracking-widest text-xs">Abbrechen</button>
                <button type="submit" className="flex-1 py-5 rounded-2xl bg-brand text-white font-black uppercase tracking-widest text-xs shadow-xl active:scale-95 transition-all">Speichern</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

const Field = ({ label, value, onChange, type = "text", select, disabled }: { label: string, value: any, onChange: (v: string) => void, type?: string, select?: string[], disabled?: boolean }) => (
  <div className="space-y-2">
    <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">{label}</label>
    {select ? (
      <select disabled={disabled} value={value} onChange={e => onChange(e.target.value)} className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-5 py-4 outline-none focus:ring-1 focus:ring-brand text-sm text-white appearance-none">
        {select.map(s => <option key={s} value={s}>{s}</option>)}
      </select>
    ) : (
      <input disabled={disabled} required type={type} value={value} onChange={e => onChange(e.target.value)} className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-5 py-4 outline-none focus:ring-1 focus:ring-brand text-sm text-white" />
    )}
  </div>
);

export default AllSites;

