        ) : active ? (
           <div className="text-[9px] font-black text-orange-400 uppercase tracking-widest flex items-center gap-2">
              <div className="w-1.5 h-1.5 rounded-full bg-orange-400 animate-ping"></div>
              Untersuchung läuft
           </div>
        ) : null}
      </div>
    </div>
  );
};

