import React from 'react';
import { AppState, PublicSystem, Incident, StatusType } from '../types';

interface Props {
  state: AppState;
  onUpdatePublic: (p: PublicSystem[]) => void;
  onUpdateIncidents: (i: Incident[]) => void;
}

const PublicManagement: React.FC<Props> = ({ state, onUpdatePublic, onUpdateIncidents }) => {

  const togglePublicStatus = (id: string) => {
      const nextStatus = (status: StatusType): StatusType => {
          if (status === 'operational') return 'degraded';
          if (status === 'degraded') return 'partial';
          if (status === 'partial') return 'major';
          if (status === 'major') return 'maintenance';
          return 'operational';
      };

      const updated = state.publicSystems.map(s => {
          if (s.id === id) {
              const newStat = nextStatus(s.status);
              const newHistory = [...s.history];
              if (newHistory.length > 0) {
                  newHistory[newHistory.length - 1] = newStat;
              }
              return { ...s, status: newStat, history: newHistory };
          }
          return s;
      });
      onUpdatePublic(updated);
  };

  const handleResolveIncident = (id: string) => {
    const updatedIncidents = state.incidents.map(inc => 
      inc.id === id ? { 
        ...inc, 
        status: 'resolved' as const,
        resolvedDate: new Date().toISOString().split('T')[0],
        resolvedTime: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      } : inc
    );
    onUpdateIncidents(updatedIncidents);
  };

  const handleDeleteIncident = (id: string) => {
    if (confirm('Möchten Sie diesen Vorfall wirklich dauerhaft löschen?')) {
        onUpdateIncidents(state.incidents.filter(i => i.id !== id));
    }
  };

  const getStatusLabelDE = (status: StatusType) => {
    switch (status) {
      case 'operational': return 'Betrieb';
      case 'degraded': return 'Leistungsminderung';
      case 'partial': return 'Teilausfall';
      case 'major': return 'Grösserer Ausfall';
      case 'maintenance': return 'Wartung';
      default: return status;
    }
  };

  return (
    <div className="space-y-10 animate-in fade-in duration-500">
      <div>
        <h1 className="text-3xl font-black tracking-tight text-white">Öffentliche Steuerung</h1>
        <p className="text-zinc-500 mt-1">Status der Kernsysteme verwalten. Vorfälle werden nun automatisch durch KI erstellt.</p>
      </div>

      <section className="bg-dark-900 border border-dark-800 rounded-3xl p-8 shadow-xl">
        <h2 className="text-xl font-bold mb-8">Manuelle System-Überschreibung</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            {state.publicSystems.map(system => {
                const hasActiveIncident = state.incidents.some(inc => inc.systemId === system.id && inc.status === 'active');
                return (
                    <div key={system.id} className={`p-6 bg-dark-950 border rounded-2xl flex flex-col gap-4 group transition-all ${hasActiveIncident ? 'border-brand/40 shadow-[0_0_20px_rgba(2,141,134,0.1)]' : 'border-dark-800'}`}>
                        <div className="flex items-center justify-between">
                            <div className="flex flex-col">
                                <p className="font-bold text-base text-zinc-100">{system.name}</p>
                                {hasActiveIncident && (
                                    <span className="text-[9px] font-black text-brand uppercase tracking-tighter">Autom. Vorfall aktiv</span>
                                )}
                            </div>
                            <div className={`w-3 h-3 rounded-full ${
                              system.status === 'operational' ? 'bg-brand' : 
                              system.status === 'degraded' ? 'bg-yellow-400' : 
                              system.status === 'partial' ? 'bg-orange-500' : 
                              system.status === 'maintenance' ? 'bg-indigo-500' : 
                              'bg-rose-500'
                            } animate-pulse`}></div>
                        </div>
                        <div className="flex items-center justify-between">
                            <p className={`text-[10px] font-black uppercase tracking-widest ${
                              system.status === 'operational' ? 'text-brand' : 
                              system.status === 'degraded' ? 'text-yellow-400' : 
                              system.status === 'partial' ? 'text-orange-500' : 
                              system.status === 'maintenance' ? 'text-indigo-400' : 
                              'text-rose-500'
                            }`}>
                                {getStatusLabelDE(system.status)}
                            </p>
                            <button
                                onClick={() => togglePublicStatus(system.id)}
                                className="text-xs font-black uppercase tracking-tighter text-zinc-400 hover:text-white bg-dark-800 hover:bg-dark-700 px-4 py-2 rounded-xl transition-all"
                            >
                                Ändern
                            </button>
                        </div>
                    </div>
                );
            })}
        </div>
      </section>

      <section className="bg-dark-900 border border-dark-800 rounded-3xl p-8 shadow-xl">
        <h2 className="text-xl font-bold mb-2">Vorfall-Archiv</h2>
        <p className="text-zinc-500 text-sm mb-10">Diese Liste wird automatisch durch die AI-Infrastrukturprüfung gepflegt.</p>
        <div className="space-y-4">
            {state.incidents.length > 0 ? (
                [...state.incidents].reverse().map(incident => (
                    <div key={incident.id} className={`flex items-center justify-between p-6 bg-dark-950 border rounded-2xl group transition-all ${incident.status === 'active' ? 'border-orange-500/30' : 'border-dark-800'}`}>
                        <div className="flex items-center gap-6">
                            <div className={`w-12 h-12 bg-dark-900 rounded-xl flex items-center justify-center font-black border border-dark-800 ${incident.status === 'active' ? 'text-orange-500' : 'text-zinc-500'}`}>
                                {incident.status === 'active' ? '!' : '✓'}
                            </div>
                            <div>
                                <div className="flex items-center gap-3">
                                    <p className="font-bold text-zinc-100">{incident.title}</p>
                                    <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded ${incident.status === 'active' ? 'bg-orange-500/20 text-orange-400' : 'bg-brand/20 text-brand'}`}>
