                        <div className="flex items-center gap-3">
                            {incident.status === 'active' && (
                                <button onClick={() => handleResolveIncident(incident.id)} className="text-brand hover:text-brand/80 text-[10px] font-black uppercase tracking-widest bg-brand/5 px-4 py-2 rounded-xl transition-all border border-brand/20">Beheben</button>
                            )}
                            <button onClick={() => handleDeleteIncident(incident.id)} className="text-rose-500 hover:text-rose-400 text-[10px] font-black uppercase tracking-widest bg-rose-500/5 px-4 py-2 rounded-xl transition-all">Löschen</button>
                        </div>
