export const BRAND_COLOR = '#028D86';

const generateHistory = (length: number, failChance: number = 0.05): StatusType[] => {
  return Array.from({ length }, () => {
    const r = Math.random();
    if (r < failChance / 2) return 'major';
    if (r < failChance) return 'partial';
    return 'operational';
  });
};

export const INITIAL_PUBLIC_SYSTEMS: PublicSystem[] = [
  { id: '1', name: 'Domäne', status: 'operational', history: generateHistory(24) },
  { id: '2', name: 'Hosting', status: 'operational', history: generateHistory(24) },
  { id: '3', name: 'Server', status: 'operational', history: generateHistory(24) },
  { id: '4', name: 'E-Mail', status: 'operational', history: generateHistory(24) },
];

