import { AppState, Incident, User } from './types';
import { INITIAL_PUBLIC_SYSTEMS, INITIAL_MONITORED_SITES } from './constants';

const STORAGE_KEY = 'madex_status_db';

export const getStore = (): AppState => {
  const data = localStorage.getItem(STORAGE_KEY);
  if (!data) {
    const initialState: AppState = {
      publicSystems: INITIAL_PUBLIC_SYSTEMS,
      monitoredSites: [], // Start empty as requested
      incidents: [],
      users: [], // Start empty as requested
      settings: { 
        discordWebhook: '',
        isTempLoginEnabled: true,
        tempAdminDisabled: false,
        checkInterval: 10,
        identity: {
          brandName: 'Madex Status',
          logo: '',
          icon: '',
          favicon: ''
        },
        dbConfig: {
          host: '',
          username: '',
          password: '',
          databaseName: '',
          isConnected: false
        }
      }
    };
    saveStore(initialState);
    return initialState;
  }
  const parsed = JSON.parse(data);
  if (!parsed.incidents) parsed.incidents = [];
  if (!parsed.users) parsed.users = [];
  if (!parsed.settings.checkInterval) parsed.settings.checkInterval = 10;
  if (parsed.settings.tempAdminDisabled === undefined) parsed.settings.tempAdminDisabled = false;
  if (!parsed.settings.identity) {
    parsed.settings.identity = { brandName: 'Madex Status' };
  }
  return parsed;
};

export const saveStore = (state: AppState) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
};

export const notifyDiscord = async (webhookUrl: string, message: string, status: 'online' | 'offline' | 'warning' = 'online') => {
  if (!webhookUrl) return;

  const color = status === 'online' ? 0x028D86 : status === 'warning' ? 0xF97316 : 0xE11D48;
  const icon = status === 'online' ? '✅' : status === 'warning' ? '⚠️' : '🚨';

  const embed = {
    title: `${icon} Madex Status Update`,
    description: message,
    color: color,
    timestamp: new Date().toISOString(),
    footer: {
      text: "Madex IT Solutions Monitoring",
      icon_url: "https://madex-it.ch/favicon.ico"
    }
  };

  try {
    await fetch(webhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ embeds: [embed] }),
    });
  } catch (error) {
    console.error('Discord notification failed:', error);
  }
};

import React from 'react';
import { AppState, Incident, StatusType } from '../types';

interface Props {
  state: AppState;
  onUpdatePublic: (p: any) => void;
  onUpdateIncidents: (i: Incident[]) => void;
}

const PublicManagement: React.FC<Props> = ({ state, onUpdateIncidents }) => {

  const handleResolveIncident = (id: string) => {
    const updatedIncidents = state.incidents.map(inc => 
      inc.id === id ? { 
        ...inc, 
        status: 'resolved' as const,
        resolvedDate: new Date().toISOString().split('T')[0],
        resolvedTime: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      } : inc
    );
    onUpdateIncidents(updatedIncidents);
  };

  const handleDeleteIncident = (id: string) => {
    if (confirm('Möchten Sie diesen Vorfall wirklich dauerhaft löschen?')) {
        onUpdateIncidents(state.incidents.filter(i => i.id !== id));
    }
  };

  const getStatusLabelDE = (status: StatusType) => {
    switch (status) {
      case 'operational': return 'BETRIEB';
      case 'degraded': return 'Leistungsminderung';
      case 'partial': return 'Teilausfall';
      case 'major': return 'Grösserer Ausfall';
      case 'maintenance': return 'Wartung';
      default: return status;
    }
  };

  return (
    <div className="space-y-10 animate-in fade-in duration-500">
      <div>
        <h1 className="text-3xl font-black tracking-tight text-white">Öffentliche Steuerung</h1>
