const App: React.FC = () => {
  const [state, setState] = useState<AppState>(getStore());
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem(AUTH_KEY) === 'true';
  });
  const lastUpdateRef = useRef<number>(Date.now());
  const lastAIPollRef = useRef<number>(0);

  useEffect(() => {
    saveStore(state);
    if (state.settings.identity.favicon) {
      const link = document.querySelector("link[rel~='icon']") as HTMLLinkElement;
      if (link) link.href = state.settings.identity.favicon;
    }
  }, [state]);

  const handleLogin = () => {
    setIsAuthenticated(true);
    localStorage.setItem(AUTH_KEY, 'true');
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem(AUTH_KEY);
  };

  const fetchProviderStatuses = async () => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `CHECK SYSTEM STATUS: Verify official status of GoDaddy (status.godaddy.com) AND Hostinger (statuspage.hostinger.com). 
      IMPORTANT: DO NOT USE the words "GoDaddy" or "Hostinger" in the output.
      Return ONLY text in this format: 
      STATUS:[operational|degraded|partial|major]
      DESC:A short generic description of the problem (e.g. "Netzwerk-Verzögerung" or "Eingeschränkte Dienst-Verfügbarkeit").`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: { tools: [{ googleSearch: {} }] }
      });

      const text = response.text || "";
      const combinedStatus = (text.match(/STATUS:(\w+)/i)?.[1]?.toLowerCase() || 'operational') as StatusType;
      const desc = text.match(/DESC:(.*)/i)?.[1] || "Allgemeine System-Störung erkannt.";

      setState(prev => {
        let nextIncidents = [...prev.incidents];
        const now = new Date();
        const dateStr = now.toISOString().split('T')[0];
        const timeStr = now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

        const nextPublic = prev.publicSystems.map(system => {
          const statusChanged = system.status !== combinedStatus;

          if (statusChanged && combinedStatus !== 'operational' && combinedStatus !== 'maintenance') {
            const existing = nextIncidents.find(inc => inc.systemId === system.id && inc.status === 'active' && (inc.title === 'Dienst-Unterbrechung' || inc.title === 'Leistungsminderung'));
            if (!existing) {
              nextIncidents.push({
                id: 'auto-' + Math.random().toString(36).substr(2, 9),
                date: dateStr,
                time: timeStr,
                title: combinedStatus === 'major' ? 'Dienst-Unterbrechung' : 'Leistungsminderung',
                description: desc,
                systemId: system.id,
                status: 'active',
                impactStatus: combinedStatus
              });
            }
          } else if (statusChanged && combinedStatus === 'operational') {
            nextIncidents = nextIncidents.map(inc => {
              if (inc.systemId === system.id && inc.status === 'active' && (inc.title === 'Dienst-Unterbrechung' || inc.title === 'Leistungsminderung')) {
                return { 
                  ...inc, 
                  status: 'resolved', 
                  resolvedDate: dateStr, 
                  resolvedTime: timeStr 
                };
              }
              return inc;
            });
          }

          const nextHistory = [...system.history.slice(1), combinedStatus];
          return { ...system, status: combinedStatus, history: nextHistory };
        });

        return { ...prev, publicSystems: nextPublic, incidents: nextIncidents };
      });
    } catch (err) {
      console.error("AI Provider check failed:", err);
    }
  };

  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      const isFiveMinPassed = now - lastUpdateRef.current >= 300000;
      const isAIPollDue = now - lastAIPollRef.current >= (state.settings.checkInterval * 60000);

      if (isAIPollDue) {
        lastAIPollRef.current = now;
        fetchProviderStatuses();
      }

      setState(prev => {
        const nextSites = prev.monitoredSites.map(site => {
            const jitter = Math.floor(Math.random() * 20) - 10;
            const currentRT = site.responseTime[site.responseTime.length - 1];
            const newRT = Math.max(30, currentRT + jitter);
            let newStatus = site.status;
            if (Math.random() < 0.002) { 
                const oldStatus = site.status;
                newStatus = site.status === 'online' ? 'offline' : 'online';
                if (prev.settings.discordWebhook && oldStatus !== newStatus) {
                    notifyDiscord(prev.settings.discordWebhook, `${site.companyName} is now ${newStatus.toUpperCase()}`, newStatus);
                }
            }
            let nextHistory = [...site.history];
            let nextResponseTimes = [...site.responseTime];
            if (isFiveMinPassed) {
              nextHistory = [...site.history.slice(1), newStatus];
              nextResponseTimes = [...site.responseTime.slice(1), newRT];
            } else {
              nextResponseTimes[nextResponseTimes.length - 1] = newRT;
            }
            return { ...site, responseTime: nextResponseTimes, history: nextHistory, status: newStatus };
        });
        if (isFiveMinPassed) lastUpdateRef.current = now;
        return { ...prev, monitoredSites: nextSites };
      });
    }, 10000);
    return () => clearInterval(interval);
  }, [state.settings.checkInterval]);

  const handleUpdateSites = (sites: MonitoredSite[]) => setState(prev => ({ ...prev, monitoredSites: sites }));
  const handleUpdateSettings = (settings: AppSettings) => setState(prev => ({ ...prev, settings }));
  const handleUpdatePublic = (publicSystems: PublicSystem[]) => setState(prev => ({ ...prev, publicSystems }));
  const handleUpdateIncidents = (incidents: Incident[]) => setState(prev => ({ ...prev, incidents }));
  const handleUpdateUsers = (users: User[]) => setState(prev => ({ ...prev, users }));

  return (
    <BrowserRouter>
      <Suspense fallback={<LoadingFallback />}>
        <Routes>
          <Route path="/" element={<PublicStatus state={state} />} />
          <Route path="/madexadm" element={<Login state={state} isAuthenticated={isAuthenticated} onLogin={handleLogin} />} />

          <Route path="/admindashboard" element={
            <ProtectedRoute isAuthenticated={isAuthenticated}>
              <DashboardLayout state={state} onLogout={handleLogout}>
                <Dashboard state={state} />
              </DashboardLayout>
            </ProtectedRoute>
          } />

          <Route path="/sites" element={
            <ProtectedRoute isAuthenticated={isAuthenticated}>
              <DashboardLayout state={state} onLogout={handleLogout}>
                <AllSites state={state} onUpdate={handleUpdateSites} />
              </DashboardLayout>
            </ProtectedRoute>
          } />

          <Route path="/sites/:id" element={
            <ProtectedRoute isAuthenticated={isAuthenticated}>
              <DashboardLayout state={state} onLogout={handleLogout}>
                <SiteProfile state={state} onUpdateSites={handleUpdateSites} />
              </DashboardLayout>
            </ProtectedRoute>
          } />

          <Route path="/public-management" element={
            <ProtectedRoute isAuthenticated={isAuthenticated}>
              <DashboardLayout state={state} onLogout={handleLogout}>
                <PublicManagement 
                  state={state} 
                  onUpdatePublic={handleUpdatePublic} 
                  onUpdateIncidents={handleUpdateIncidents} 
                />
              </DashboardLayout>
            </ProtectedRoute>
          } />

          <Route path="/users" element={
            <ProtectedRoute isAuthenticated={isAuthenticated}>
              <DashboardLayout state={state} onLogout={handleLogout}>
                <UserManagement state={state} onUpdateUsers={handleUpdateUsers} />
              </DashboardLayout>
            </ProtectedRoute>
          } />

          <Route path="/settings" element={
            <ProtectedRoute isAuthenticated={isAuthenticated}>
              <DashboardLayout state={state} onLogout={handleLogout}>
                <Settings state={state} onUpdateSettings={handleUpdateSettings} />
              </DashboardLayout>
            </ProtectedRoute>
          } />

          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </Suspense>
    </BrowserRouter>
  );
};

export default App;

import React, { useState } from 'react';
import { AppState, AppSettings, DatabaseConfig, SiteIdentity } from '../types';
import { Shield, Activity, Globe } from '../components/Icons';

interface Props {
  state: AppState;
  onUpdateSettings: (s: AppSettings) => void;
}

const Settings: React.FC<Props> = ({ state, onUpdateSettings }) => {
  const [webhook, setWebhook] = useState(state.settings.discordWebhook);
  const [checkInterval, setCheckInterval] = useState(state.settings.checkInterval);
  const [identity, setIdentity] = useState<SiteIdentity>(state.settings.identity);
  const [dbConfig, setDbConfig] = useState<DatabaseConfig>(state.settings.dbConfig);
  const [tempAdminDisabled, setTempAdminDisabled] = useState(state.settings.tempAdminDisabled);

  const [isSaved, setIsSaved] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, key: keyof SiteIdentity) => {
    const file = e.target.files?.[0];
    if (file) {
      // In a production app, this would be an API call to upload to /Uploads/
      // For this demo, we use the Base64 representation but label it as a conceptual path
      const reader = new FileReader();
      reader.onloadend = () => {
        const result = reader.result as string;
        setIdentity(prev => ({ ...prev, [key]: result }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveAll = () => {
    onUpdateSettings({ 
      ...state.settings, 
      discordWebhook: webhook,
      checkInterval: checkInterval,
      identity: identity,
      dbConfig: dbConfig,
      tempAdminDisabled: tempAdminDisabled
    });
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 2000);
  };

  const testDatabaseConnection = async () => {
    setIsConnecting(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    setDbConfig(prev => ({ ...prev, isConnected: true }));
    setIsConnecting(false);
  };

  return (
    <div className="space-y-10 animate-in fade-in duration-500 pb-24">
      <div className="flex items-center justify-between border-b border-dark-800 pb-8">
