          onClick={handleSaveAll}
          className="bg-brand hover:brightness-110 text-white px-10 py-4 rounded-2xl font-black uppercase tracking-widest text-xs transition-all shadow-xl active:scale-95"
        >
          {isSaved ? '✓ Änderungen Gespeichert' : 'Konfiguration Speichern'}
