import React, { useState } from 'react';
import { AppState, AppSettings, DatabaseConfig, SiteIdentity } from '../types';
import { Shield, Activity, Globe } from '../components/Icons';

interface Props {
  state: AppState;
  onUpdateSettings: (s: AppSettings) => void;
}

const Settings: React.FC<Props> = ({ state, onUpdateSettings }) => {
  const [webhook, setWebhook] = useState(state.settings.discordWebhook);
  const [checkInterval, setCheckInterval] = useState(state.settings.checkInterval);
  const [identity, setIdentity] = useState<SiteIdentity>(state.settings.identity);
  const [dbConfig, setDbConfig] = useState<DatabaseConfig>(state.settings.dbConfig);
  const [tempAdminDisabled, setTempAdminDisabled] = useState(state.settings.tempAdminDisabled);

  const [isSaved, setIsSaved] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, key: keyof SiteIdentity) => {
    const file = e.target.files?.[0];
    if (file) {
      // In a real backend scenario, we would POST this file to a server 
      // which would save it to /public/Uploads/ and return the URL.
      // For this demo, we use Base64 to keep the preview working, 
      // but the UI reflects that it belongs in the Uploads folder.
      const reader = new FileReader();
      reader.onloadend = () => {
        const result = reader.result as string;
        setIdentity(prev => ({ ...prev, [key]: result }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveAll = () => {
    onUpdateSettings({ 
      ...state.settings, 
      discordWebhook: webhook,
      checkInterval: checkInterval,
      identity: identity,
      dbConfig: dbConfig,
      tempAdminDisabled: tempAdminDisabled
    });
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 2000);
  };

  const testDatabaseConnection = async () => {
    setIsConnecting(true);
    // Simulation of DB connection
    await new Promise(resolve => setTimeout(resolve, 1500));
    setDbConfig(prev => ({ ...prev, isConnected: true }));
    setIsConnecting(false);
  };

  return (
    <div className="space-y-10 animate-in fade-in duration-500 pb-24">
      <div className="flex items-center justify-between border-b border-dark-800 pb-8">
        <div>
          <h1 className="text-4xl font-black tracking-tight text-white">System-Einstellungen</h1>
          <p className="text-zinc-500 mt-2 font-medium">Verwalten Sie Branding, Synchronisierungs-Intervalle und Datenbank-Verbindungen.</p>
        </div>
        <button
          onClick={handleSaveAll}
          className="bg-brand hover:brightness-110 text-white px-10 py-4 rounded-2xl font-black uppercase tracking-widest text-xs transition-all shadow-xl active:scale-95"
        >
          {isSaved ? '✓ Änderungen Gespeichert' : 'Konfiguration Speichern'}
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <section className="bg-dark-900 border border-dark-800 rounded-[32px] p-10 shadow-xl space-y-8">
          <div className="flex items-center gap-5">
              <div className="w-14 h-14 bg-brand/10 rounded-2xl flex items-center justify-center text-brand">
                  <Activity className="w-8 h-8" />
              </div>
              <div>
                <h2 className="text-xl font-black text-white tracking-tight">Identity & Assets</h2>
                <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">Speicherort: /public/Uploads/</p>
              </div>
          </div>
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Markenname</label>
              <input
                type="text"
                value={identity.brandName}
                onChange={e => setIdentity({...identity, brandName: e.target.value})}
                className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-6 py-4 focus:ring-1 focus:ring-brand outline-none text-white font-bold"
              />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
               <UploadBox label="Logo" current={identity.logo} onUpload={(e) => handleFileUpload(e, 'logo')} />
               <UploadBox label="Icon" current={identity.icon} onUpload={(e) => handleFileUpload(e, 'icon')} />
               <UploadBox label="Favicon" current={identity.favicon} onUpload={(e) => handleFileUpload(e, 'favicon')} />
            </div>
            <div className="p-4 bg-dark-950/50 border border-dashed border-dark-800 rounded-2xl text-center">
              <p className="text-[9px] text-zinc-500 uppercase tracking-[0.2em] leading-relaxed">
                Hinweis: Hochgeladene Dateien werden automatisch in den <span className="text-brand font-black">/Uploads/</span> Ordner verschoben und von dort referenziert.
              </p>
            </div>
          </div>
        </section>

        <section className="bg-dark-900 border border-dark-800 rounded-[32px] p-10 shadow-xl space-y-8">
          <div className="flex items-center gap-5">
              <div className="w-14 h-14 bg-amber-500/10 rounded-2xl flex items-center justify-center text-amber-500">
                  <Globe className="w-8 h-8" />
              </div>
              <h2 className="text-xl font-black text-white tracking-tight">AI Check & Alerts</h2>
          </div>
          <div className="space-y-6">
            <div className="p-6 bg-dark-950 border border-dark-800 rounded-2xl">
