                <span className="text-2xl font-black text-brand w-16 text-right">{checkInterval}m</span>
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">Discord Webhook</label>
              <input
                type="text"
