                <div>
                  <h2 className="text-xl font-black text-white tracking-tight">Datenbank-Infrastruktur</h2>
                  <p className="text-xs text-zinc-500 font-medium">Konfigurieren Sie die Persistenz für Monitore und Benutzerkonten.</p>
                </div>
            </div>
            <button 
              onClick={testDatabaseConnection} 
              disabled={isConnecting}
              className={`px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                dbConfig.isConnected ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/20 shadow-lg shadow-emerald-500/10' : 'bg-dark-950 border border-dark-800 text-zinc-400 hover:border-brand/40'
              }`}
            >
              {isConnecting ? 'Verbinde...' : dbConfig.isConnected ? '✓ Verbundn' : 'SYNC & CONNECT'}
            </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">DB HOST</label>
              <input
                type="text"
                value={dbConfig.host}
                onChange={e => setDbConfig({...dbConfig, host: e.target.value})}
