                placeholder="localhost"
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">DATABASE NAME</label>
              <input
                type="text"
                value={dbConfig.databaseName}
                onChange={e => setDbConfig({...dbConfig, databaseName: e.target.value})}
                className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-5 py-3 outline-none focus:ring-1 focus:ring-brand text-sm text-white font-mono"
                placeholder="madex_db"
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">USERNAME</label>
              <input
                type="text"
                value={dbConfig.username}
                onChange={e => setDbConfig({...dbConfig, username: e.target.value})}
                className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-5 py-3 outline-none focus:ring-1 focus:ring-brand text-sm text-white font-mono"
                placeholder="db_user"
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest ml-1">PASSWORD</label>
              <input
                type="password"
                value={dbConfig.password}
                onChange={e => setDbConfig({...dbConfig, password: e.target.value})}
                className="w-full bg-dark-950 border border-dark-800 rounded-2xl px-5 py-3 outline-none focus:ring-1 focus:ring-brand text-sm text-white font-mono"
                placeholder="••••••••"
              />
            </div>
          </div>

          <div className="pt-8 mt-8 border-t border-dark-800 flex flex-col md:flex-row md:items-center justify-between gap-6">
              <div className="max-w-xl">
                <p className="text-sm font-bold text-white mb-1">Temporary Admin Login (Admin/password)</p>
                <p className="text-xs text-zinc-500 leading-relaxed">Der temporäre Zugriff ist für die Erstkonfiguration gedacht. Sobald Sie neue Administratoren in der verbundenen Datenbank erstellt haben, sollten Sie diesen Zugang aus Sicherheitsgründen deaktivieren.</p>
              </div>
              <button 
                onClick={() => setTempAdminDisabled(!tempAdminDisabled)}
                className={`px-8 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
                  tempAdminDisabled ? 'bg-rose-500/10 text-rose-500 border border-rose-500/20' : 'bg-brand text-white shadow-xl shadow-brand/20'
                }`}
              >
                {tempAdminDisabled ? 'Temporärer Zugang Deaktiviert' : 'Temporärer Zugang Aktiv'}
              </button>
          </div>
        </section>
      </div>
    </div>
  );
};

